import time
import functools


def retry_with_exponential_backoff(max_retries=3, delay=1.0, backoff=2.0):
    def decorator(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            retries = 0
            while retries < max_retries:
                try:
                    return func(*args, **kwargs)
                except Exception as e:
                    retries += 1
                    time.sleep(delay)
                    delay *= backoff
                    if retries == max_retries:
                        raise e
        return wrapper
    return decorator
