func main() {
	if len(os.Args)!= 3 {
		fmt.Println("Usage: rdns <start_ip> <end_ip>")
		os.Exit(1)
	}

	startIP := os.Args[1]
	endIP := os.Args[2]

	ip := startIP
	for {
		hostnames, err := net.LookupAddr(ip)
		if err == nil {
			fmt.Printf("%s: %s\n", ip, strings.Join(hostnames, ", "))
		}

		if ip == endIP {
			break
		}

		ip = nextIP(ip)
	}
}

func nextIP(ip string) string {
	parts := strings.Split(ip, ".")
	lastOctet := parts[3]

	nextOctet := fmt.Sprintf("%d", atoi(lastOctet)+1)

	parts[3] = nextOctet
	return strings.Join(parts, ".")
}

func atoi(s string) int {
	val := 0
	for _, c := range s {
		val = val*10 + int(c-'0')
	}
	return val
}

