use std::collections::HashSet;
use std::env;
use reqwest::Url;
use scraper::{Html, Selector};

async fn fetch_url(url: &str) -> Result<String, reqwest::Error> {
    reqwest::get(url).await?.text().await
}

fn extract_links(html: &Html) -> HashSet<String> {
    let selector = Selector::parse("a[href]").unwrap();
    html
       .select(&selector)
       .filter_map(|element| element.value().attr("href"))
       .filter_map(|url| Url::parse(url).ok())
       .filter(|url| url.has_host() && url.scheme() == "http" || url.scheme() == "https")
       .map(|url| url.into_string())
       .collect::<HashSet<_>>()
}

fn extract_forms(html: &Html) -> Vec<String> {
    let selector = Selector::parse("form").unwrap();
    html
       .select(&selector)
       .map(|element| element.html())
       .collect()
}

fn extract_inputs(html: &Html) -> Vec<String> {
    let selector = Selector::parse("input[name]").unwrap();
    html
       .select(&selector)
       .filter_map(|element| element.value().attr("name"))
       .map(|name| name.to_string())
       .collect()
}

fn crawl(start_url: &str) -> Result<(), Box<dyn std::error::Error>> {
    let mut visited = HashSet::new();
    let mut queue = vec![start_url.to_string()];

    while let Some(url) = queue.pop() {
        if!visited.contains(&url) {
            visited.insert(url.clone());
            let html = fetch_url(&url).await?;
            let document = Html::parse_document(&html);

            let links = extract_links(&document);
            let forms = extract_forms(&document);
            let inputs = extract_inputs(&document);

            println!("URL: {}", url);
            println!("Links: {:?}", links);
            println!("Forms: {:?}", forms);
            println!("Inputs: {:?}", inputs);

            queue.extend(links);
        }
    }

    Ok(())
}

#[tokio::main]
async fn main() {
    let args: Vec<String> = env::args().collect();
    if args.len()!= 2 {
        eprintln!("Usage: {} <start_url>", args[0]);
        std::process::exit(1);
    }

    if let Err(err) = crawl(&args[1]) {
        eprintln!("Error: {}", err);
        std::process::exit(1);
    }
}
