template <typename Callback>
void debounceAndThrottle(Callback callback, milliseconds debounceDuration, milliseconds throttleDuration) {
    static steady_clock::time_point lastCallTime = steady_clock::now() - throttleDuration;
    static steady_clock::time_point lastExecutionTime = steady_clock::now();

    auto currentTime = steady_clock::now();

    if (currentTime - lastCallTime >= throttleDuration) {
        lastCallTime = currentTime;

        if (currentTime - lastExecutionTime >= debounceDuration) {
            lastExecutionTime = currentTime;
            callback();
        }
    }
