            if (maze[i][j] == 'S') {
                q.push({i, j});
                break;
            }
        }
    }
    vector<vector<int>> dirs = {{0, 1}, {0, -1}, {1, 0}, {-1, 0}};
    int steps = 0;
    while (!q.empty()) {
        int size = q.size();
        for (int i = 0; i < size; ++i) {
            auto [x, y] = q.front();
            q.pop();
            if (maze[x][y] == 'E') return steps;
            for (auto& dir : dirs) {
                int nx = x + dir[0], ny = y + dir[1];
                if (nx >= 0 && nx < m && ny >= 0 && ny < n && maze[nx][ny]!= '#') {
                    q.push({nx, ny});
                    maze[nx][ny] = '#';
                }
            }
        }
        ++steps;
    }
    return -1;
}

