class Graph {
    int vertices;
    List<List<Edge>> adjList;
    public Graph(int vertices) {
        this.vertices = vertices;
        adjList = new ArrayList<>(vertices);
        for (int i = 0; i < vertices; i++)
            adjList.add(new LinkedList<>());
    }
    public void addEdge(int src, int dest, int weight) {
        Edge edge = new Edge(dest, weight);
        adjList.get(src).add(edge);
    }
}

class Dijkstra {
    private static final int INF = Integer.MAX_VALUE;
    public static void dijkstra(Graph graph, int src, int dest) {
        boolean[] visited = new boolean[graph.vertices];
        int[] dist = new int[graph.vertices];
        Arrays.fill(dist, INF);
        dist[src] = 0;
        PriorityQueue<Edge> pq = new PriorityQueue<>(Comparator.comparingInt(e -> e.weight));
        pq.add(new Edge(src, 0));
        while (!pq.isEmpty()) {
            int u = pq.poll().dest;
            visited[u] = true;
            for (Edge edge : graph.adjList.get(u)) {
                int v = edge.dest;
                int weight = edge.weight;
                if (!visited[v] && dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight;
                    pq.add(new Edge(v, dist[v]));
                }
            }
        }
        System.out.println("Shortest distance from " + src + " to " + dest + ": " + dist[dest]);
    }
}

class Main {
    public static void main(String[] args) {
        Graph graph = new Graph(5);
        graph.addEdge(0, 1, 10);
        graph.addEdge(0, 2, 3);
