use std::fs;
use std::io::prelude::*;
use std::path::PathBuf;
use zip::write::FileOptions;
 n compress_directory(dir_path: &str) -> Vec<u8> {
    let mut zip_buffer = Vec::new();
    let mut zip_writer = zip::ZipWriter::new(zip_buffer);

    let options = FileOptions::default().compression_method(zip::CompressionMethod::Deflated);
    let mut path_prefix = PathBuf::from(dir_path);
    path_prefix.pop();

    fn add_directory_contents(zip_writer: &mut zip::ZipWriter<&mut Vec<u8>>, dir_path: &PathBuf, options: &FileOptions, path_prefix: &PathBuf) -> zip::result::ZipResult<()> {
        for entry in fs::read_dir(dir_path)? {
            let entry = entry?;
            let path = entry.path();
            let name = path.strip_prefix(path_prefix).unwrap().to_str().unwrap();

            if path.is_file() {
                zip_writer.start_file(name, *options)?;
                let mut file = fs::File::open(path)?;
                io::copy(&mut file, zip_writer)?;
            } else if path.is_dir() {
                add_directory_contents(zip_writer, &path, options, path_prefix)?;
            }
        }
        Ok(())
    }

    add_directory_contents(&mut zip_writer, &PathBuf::from(dir_path), &options, &path_prefix).unwrap();
    zip_writer.finish().unwrap();

    zip_buffer
}
