namespace app\components;

class ApiProxy extends \yii\base\Component
{
    public $upstreamApiUrl;
    public $cacheDuration = 3600; // seconds

    public function handleRequest($endpoint, $params = [])
    {
        $cacheKey = $this->buildCacheKey($endpoint, $params);
        $cachedResponse = \Yii::$app->cache->get($cacheKey);

        if ($cachedResponse === false) {
            $response = $this->forwardRequest($endpoint, $params);
            \Yii::$app->cache->set($cacheKey, $response, $this->cacheDuration);
            return $response;
        }

        return $cachedResponse;
    }

    protected function buildCacheKey($endpoint, $params)
    {
        $paramString = http_build_query($params);
        return "api-proxy:$endpoint:$paramString";
    }

    protected function forwardRequest($endpoint, $params)
    {
        $url = "$this->upstreamApiUrl/$endpoint". ($params? '?'. http_build_query($params) : '');
        $response = file_get_contents($url);
        return $response;
    }
}
