from functools import wraps
import time
import hashlib
import hmac

def rate_limit(max_requests, window_seconds):
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            client_key = request.headers.get('X-Client-Key')
            if not client_key:
                return jsonify({'error': 'Missing X-Client-Key header'}), 400

            current_time = int(time.time())
            signature = hmac.new(client_key.encode(), str(current_time).encode(), hashlib.sha256).hexdigest()

            request_timestamps = request.headers.get('X-Request-Timestamps', '')
            request_count = len(request_timestamps.split(','))

            if request_count >= max_requests:
                return make_response(jsonify({'error': 'Rate limit exceeded'}), 429)

            if request_timestamps:
                request_timestamps += ','
            request_timestamps += f'{current_time}-{signature}'

            response = f(*args, **kwargs)
            response.headers['X-Request-Timestamps'] = request_timestamps
            return response
        return wrapped
    return decorator

app = Flask(__name__)

@app.route('/api/data')
@rate_limit(max_requests=5, window_seconds=60)
def get_data():
    return jsonify({'data': 'some data'})

if __name__ == '__main__':
    app.run()
