def stream_csv():
    file_path = 'large_file.csv'
    chunk_size = 8192  # 8 KB chunks

    def generate():
        with open(file_path, 'rb') as f:
            chunk = f.read(chunk_size)
            while chunk:
                yield chunk
                chunk = f.read(chunk_size)

    return Response(generate(), mimetype='text/csv')

