trait Repository<T> {
    fn get_all(&self) -> &Vec<T>;
    fn get_by_id(&self, id: u32) -> Option<&T>;
    fn add(&mut self, item: T);
    fn update(&mut self, id: u32, item: T);
    fn delete(&mut self, id: u32);
}

struct Database<T> {
    data: Vec<T>,
}

impl<T: Clone + PartialEq> Repository<T> for Database<T> {
    fn get_all(&self) -> &Vec<T> {
        &self.data
    }

    fn get_by_id(&self, id: u32) -> Option<&T> {
        self.data.iter().find(|item| item.id == id)
    }

    fn add(&mut self, item: T) {
        self.data.push(item);
    }

    fn update(&mut self, id: u32, item: T) {
        if let Some(index) = self.data.iter().position(|x| x.id == id) {
            self.data[index] = item;
        }
    }

    fn delete(&mut self, id: u32) {
        if let Some(index) = self.data.iter().position(|x| x.id == id) {
            self.data.remove(index);
        }
    }
}
