import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;

public class HashMap<K, V> {

    private static final double LOAD_FACTOR = 0.75;
    private List<KeyValuePair<K, V>>[] table;
    private int size;

    public HashMap() {
        table = new ArrayList[10];
        size = 0;
    }

    public void put(K key, V value) {
        if (size + 1 >= table.length * LOAD_FACTOR) {
            resize();
        }

        int index = getIndex(key);
        List<KeyValuePair<K, V>> chain = table[index];
        if (chain == null) {
            chain = new LinkedList<KeyValuePair<K, V>>();
            table[index] = chain;
        }

        for (KeyValuePair<K, V> pair : chain) {
            if (pair.key.equals(key)) {
                pair.value = value;
                return;
            }
        }

        chain.add(new KeyValuePair<K, V>(key, value));
        size++;
    }

    public V get(K key) {
        int index = getIndex(key);
        List<KeyValuePair<K, V>> chain = table[index];
        if (chain!= null) {
            for (KeyValuePair<K, V> pair : chain) {
                if (pair.key.equals(key)) {
                    return pair.value;
                }
            }
        }
        return null;
    }

    private int getIndex(K key) {
        int hashCode = key.hashCode();
        int index = hashCode % table.length;
        return index;
    }

    private void resize() {
        List<KeyValuePair<K, V>>[] newTable = new ArrayList[table.length * 2];
        for (List<KeyValuePair<K, V>> chain : table) {
            if (chain!= null) {
                for (KeyValuePair<K, V> pair : chain) {
                    int index = pair.key.hashCode() % newTable.length;
                    List<KeyValuePair<K, V>> newChain = newTable[index];
                    if (newChain == null) {
                        newChain = new LinkedList<KeyValuePair<K, V>>();
                        newTable[index] = newChain;
                    }
                    newChain.add(pair);
                }
            }
        }
        table = newTable;
    }

    private static class KeyValuePair<K, V> {
        K key;
        V value;

        public KeyValuePair(K key, V value) {
            this.key = key;
            this.value = value;
        }
    }
}
