import requests
from urllib.parse import urljoin


class CachePoisoner:
    def __init__(self, base_url):
        self.base_url = base_url
        self.session = requests.Session()

    def fetch(self, path, headers=None, params=None):
        url = urljoin(self.base_url, path)
        response = self.session.get(url, headers=headers, params=params)
        return response

    def has_vary_header(self, response):
        return 'Vary' in response.headers

    def has_cache_control_header(self, response):
        return 'Cache-Control' in response.headers

    def is_cacheable(self, response):
        if not self.has_cache_control_header(response):
            return False
        cache_control = response.headers['Cache-Control']
        return 'no-store' not in cache_control and 'private' not in cache_control

    def test_poisoning(self, path, payloads):
        if not self.is_cacheable(self.fetch(path)):
            return False
        for payload in payloads:
            response = self.fetch(path, params={'cachebuster': payload})
            if self.is_cacheable(response):
                return True
        return False


if __name__ == '__main__':
    url = 'https://example.com'
    tester = CachePoisoner(url)

    with open('payloads.txt', 'r') as f:
        payloads = [line.strip() for line in f.readlines()]

    paths_to_test = ['/', '/about', '/contact', '/login', '/admin']

    for path in paths_to_test:
        if tester.test_poisoning(path, payloads):
            print(f'Potential cache poisoning detected at {urljoin(url, path)}')
