#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

#define CAPACITY 5

typedef struct Node {
    int key;
    int value;
    struct Node* prev;
    struct Node* next;
} Node;

Node* createNode(int key, int value) {
    Node* node = (Node*)malloc(sizeof(Node));
    node->key = key;
    node->value = value;
    node->prev = NULL;
    node->next = NULL;
    return node;
}

void removeNode(Node** head, Node** tail, Node* node) {
    if (*head == node)
        *head = node->next;
    if (*tail == node)
        *tail = node->prev;
    if (node->next!= NULL)
        node->next->prev = node->prev;
    if (node->prev!= NULL)
        node->prev->next = node->next;
    free(node);
}

void moveToHead(Node** head, Node* node) {
    node->next = *head;
    node->prev = NULL;
    if (*head!= NULL)
        (*head)->prev = node;
    *head = node;
}

int get(Node** head, Node** tail, int key) {
    Node* current = *head;
    while (current!= NULL) {
        if (current->key == key) {
            moveToHead(head, current);
            return current->value;
        }
        current = current->next;
    }
    return -1;
}

void put(Node** head, Node** tail, int* size, int key, int value) {
    Node* current = *head;
    while (current!= NULL) {
        if (current->key == key) {
            current->value = value;
            moveToHead(head, current);
            return;
        }
        current = current->next;
    }
    Node* newNode = createNode(key, value);
    moveToHead(head, newNode);
    (*size)++;
    if (*size > CAPACITY) {
        removeNode(head, tail, *tail);
        (*size)--;
    }
}

int main() {
    Node* head = NULL;
    Node* tail = NULL;
    int size = 0;

    put(&head, &tail, &size, 1, 10);
    put(&head, &tail, &size, 2, 20);
    printf("Value for key 1: %d\n", get(&head, &tail, 1));
    put(&head, &tail, &size, 3, 30);
    printf("Value for key 2: %d\n", get(&head, &tail, 2));
    put(&head, &tail, &size, 4, 40);
    printf("Value for key 1: %d\n", get(&head, &tail, 1));
    put(&head, &tail, &size, 5, 50);
    printf("Value for key 3: %d\n", get(&head, &tail, 3));

    return 0;
