use jsonwebtoken::{decode, Algorithm, DecodingKey, Validation};

fn main() {
    let token = "some_jwt_token";
    let key = "secret_key";

    // Define the validation criteria, explicitly specifying the expected algorithm
    let mut validation = Validation::new(Algorithm::HS256);

    // Decode the token, passing in the expected algorithm
    let decoded_token = decode::<Claims>(token, &DecodingKey::from_secret(key.as_ref()), &validation);

    match decoded_token {
        Ok(token_data) => println!("Token is valid. Claims: {:?}", token_data.claims),
