Explanation of the fix:

1. The critical change is explicitly specifying the expected signing algorithm during the validation setup. By passing `Algorithm::HS256` to `Validation::new()`, the code now requires the token to be signed using the HS256 algorithm.

2. When decoding the token, the `validation` object with the specified algorithm is passed to the `decode` function. This ensures the library will reject tokens signed with any other algorithm, including 'none'.

3. By enforcing the expected algorithm, the code is no longer vulnerable to attackers bypassing the signature check by using the 'none' algorithm. The library will now reject any token not signed with the HS256 algorithm and the provided secret key.

#include <iostream>
#include <string>
#include <boost/asio.hpp>
#include <boost/algorithm/string.hpp>

using boost::asio::ip::tcp;

std::string sendRequest(const std::string& host, const std::string& port, const std::string& resource) {
    try {
        boost::asio::io_context io_context;

        tcp::resolver resolver(io_context);
        tcp::resolver::results_type endpoints = resolver.resolve(host, port);

        tcp::socket socket(io_context);
        boost::asio::connect(socket, endpoints);

        boost::asio::streambuf request;
        std::ostream request_stream(&request);
        request_stream << "GET " << resource << " HTTP/1.1\r\n";
        request_stream << "Host: " << host << "\r\n";
        request_stream << "Accept: */*\r\n";
        request_stream << "\r\n";

        boost::asio::write(socket, request);

        boost::asio::streambuf response;
        boost::asio::read_until(socket, response, "\r\n\r\n");

        std::istream response_stream(&response);
        std::string header;
        std::string fingerprint;
        while (std::getline(response_stream, header) && header!= "\r") {
            if (boost::algorithm::starts_with(header, "Server:")) {
                fingerprint = header.substr(8);
                boost::algorithm::trim(fingerprint);
            }
        }

        return fingerprint;
    } catch (std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
        return "";
    }
}

int main(int argc, char* argv[]) {
    if (argc!= 4) {
        std::cerr << "Usage: " << argv[0] << " <host> <port> <resource>" << std::endl;
        return 1;
    }

    std::string host = argv[1];
    std::string port = argv[2];
    std::string resource = argv[3];

    std::string fingerprint = sendRequest(host, port, resource);

    if (!fingerprint.empty()) {
        std::cout << "Web server fingerprint: " << fingerprint << std::endl;
    } else {
        std::cout << "Failed to obtain web server fingerprint." << std::endl;
    }

    return 0;
}

