int longest_substring_without_repeats(char *s) {
    int n = strlen(s);
    int i, j, max_len = 0;
    int last_seen[256];
    memset(last_seen, -1, sizeof(last_seen));

    i = j = 0;
    while (j < n) {
        if (last_seen[(int)s[j]]!= -1) {
            i = (last_seen[(int)s[j]] > i)? last_seen[(int)s[j]] : i;
        }
        last_seen[(int)s[j]] = j + 1;
        max_len = (j - i + 1 > max_len)? j - i + 1 : max_len;
        j++;
    }
    return max_len;
}

