package main

import (
	"fmt"
)

// mergeSort function takes an array as input and recursively divides it into halves
func mergeSort(arr []int) []int {
	if len(arr) <= 1 {
		return arr
	}
	mid := len(arr) / 2
	left := mergeSort(arr[:mid])
	right := mergeSort(arr[mid:])
	return merge(left, right)
}

// merge function merges two sorted arrays into a single sorted array
func merge(left, right []int) []int {
	result := make([]int, 0, len(left)+len(right))
	for len(left) > 0 || len(right) > 0 {
		if len(left) == 0 {
			return append(result, right...)
		}
		if len(right) == 0 {
			return append(result, left...)
		}
		if left[0] < right[0] {
			result = append(result, left[0])
			left = left[1:]
		} else {
			result = append(result, right[0])
			right = right[1:]
		}
	}
	return result
}

func main() {
	arr := []int{38, 27, 43, 3, 9, 82, 10}
	sortedArr := mergeSort(arr)
	fmt.Println("Sorted array:", sortedArr)
}
```

Time Complexity:
- The merge sort algorithm divides the input array into two halves recursively until the base case of an array with a single element is reached. This division step takes O(log n) time.
- During the merge step, the algorithm merges the two sorted halves back into a single sorted array. This merging process takes O(n) time, as it needs to compare and merge all elements.
- Therefore, the overall time complexity of merge sort is O(n log n), as the division step happens log n times, and each time, the merge step takes O(n) time.
Space Complexity:
- Merge sort requires additional space to store the temporary arrays during the merge process. In the worst case, the algorithm needs to allocate space for n elements.
- Thus, the space complexity of merge sort is O(n).

