from graphql import GraphQLSchema, GraphQLObjectType, GraphQLString, GraphQLField, GraphQLArgument
from graphql.utilities import print_schema
from graphql.validation.rules import NoFragmentCycles

# Function to limit query depth
def depth_limit_validator(max_depth):
    def validator(ctx):
        depths = {}

        def visit_node(node, depth):
            if node not in depths or depths[node] > depth:
                depths[node] = depth
                if isinstance(node, FieldNode):
                    for arg in node.arguments:
                        visit_node(arg, depth + 1)
                    for n in node.selection_set.selections:
                        visit_node(n, depth + 1)
                elif isinstance(node, InlineFragmentNode):
                    for n in node.selection_set.selections:
                        visit_node(n, depth)
                elif isinstance(node, FragmentSpreadNode):
                    visit_node(ctx.fragments[node.name.value], depth)

        for op in ctx.document.definitions:
            if isinstance(op, OperationDefinitionNode):
                for selection in op.selection_set.selections:
                    visit_node(selection, 0)

        if any(depth > max_depth for depth in depths.values()):
            raise GraphQLError(f'Query depth limit of {max_depth} exceeded')

    return validator

# Updated schema with limited query depth
