fn main() -> io::Result<()> {
    let mut processes = vec![];
    let entries = fs::read_dir("/proc").unwrap();
    for entry in entries {
        let dir = entry.unwrap().path();
        let pid = dir.file_name().unwrap().to_string_lossy();
        if pid.chars().all(|c| c.is_digit()) {
            let status_file = dir.join("status");
            if status_file.exists() {
                let file = fs::File::open(status_file)?;
                let reader = io::BufReader::new(file);
                let mut name = String::new();
                let mut state = String::new();
                for line in reader.lines() {
                    let line = line?;
                    if line.starts_with("Name:") {
                        name = line.split_whitespace().nth(1).unwrap().to_string();
                    } else if line.starts_with("State:") {
                        state = line.split_whitespace().nth(1).unwrap().to_string();
                    }
                }
                processes.push((pid.to_string(), name, state));
            }
        }
    }
    println!("{:<8} {:<25} {:<10}", "PID", "Name", "Status");
    for (pid, name, status) in processes {
        println!("{:<8} {:<25} {:<10}", pid, name, status);
    }
    Ok(())
}
