namespace App\Http\Controllers;

class ApiProxyController extends Controller
{
    public function proxyRequest(Request $request)
    {
        $url = 'https://api.example.com/endpoint';

        try {
            // Check if the response is already cached
            $cacheKey = 'api_response_'. md5($url. serialize($request->all()));
            $cachedResponse = Cache::get($cacheKey);

            if ($cachedResponse) {
                return response()->json($cachedResponse);
            }

            // Forward the request to the upstream API
            $response = Http::get($url, $request->all());

            if ($response->successful()) {
                $data = $response->json();

                // Cache the response for future requests
                Cache::put($cacheKey, $data, now()->addMinutes(10));

                return response()->json($data);
            } else {
                throw new \Exception('Upstream API request failed.');
            }
        } catch (\Exception $e) {
            // Handle errors and return an appropriate response
            return response()->json(['error' => 'An error occurred while processing the request.'], 500);
        }
    }
}
