def get_subdomains(domain):
    subdomains = []
    try:
        response = requests.get(f'https://crt.sh/?q=%25.{domain}')
        soup = BeautifulSoup(response.content, 'html.parser')
        subdomains = re.findall(r'([a-zA-Z0-9_\.-]+\.' + domain + ')', soup.text)
    except Exception as e:
        print(f'Error: {e}')
    return subdomains


def get_ip_addresses(subdomains):
    ips = {}
    for subdomain in subdomains:
        try:
            ip = socket.gethostbyname(subdomain)
            ips[subdomain] = ip
        except Exception as e:
            print(f'Error: {e}')
    return ips


def scan_ports(ip):
    open_ports = []
    for port in range(1, 65535):
        sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        sock.settimeout(1)
        result = sock.connect_ex((ip, port))
        if result == 0:
            open_ports.append(port)
        sock.close()
    return open_ports


def generate_report(domain, subdomains, ips, open_ports):
    with open(f'{domain}_report.md', 'w') as file:
        file.write(f'# Reconnaissance Report for {domain}\n\n')
        file.write('## Subdomains:\n\n')
        for subdomain in subdomains:
            file.write(f'- {subdomain}\n')
        file.write('\n## IP Addresses:\n\n')
        for subdomain, ip in ips.items():
            file.write(f'- {subdomain}: {ip}\n')
        file.write('\n## Open Ports:\n\n')
        for ip, ports in open_ports.items():
            file.write(f'### {ip}\n\n')
            for port in ports:
                file.write(f'- {port}\n')


