    print(f'Collecting subdomains for {domain}...')
    subdomains = get_subdomains(domain)
    print(f'Collecting IP addresses for subdomains...')
    ips = get_ip_addresses(subdomains)
    open_ports = {}
    for ip in ips.values():
        print(f'Scanning ports for {ip}...')
        open_ports[ip] = scan_ports(ip)
    print('Generating report...')
    generate_report(domain, subdomains, ips, open_ports)
    print(f'Reconnaissance completed. Report saved as {domain}_report.md')


if __name__ == '__main__':
