function computeSha256(filePath, callback) {
  const hash = crypto.createHash('sha256');
  const stream = fs.createReadStream(filePath);

  stream.on('data', (data) => {
    hash.update(data);
  });

  stream.on('end', () => {
    const digest = hash.digest('hex');
    callback(null, digest);
  });

  stream.on('error', (err) => {
    callback(err);
  });
}

