#include <iostream>
#include <vector>
#include <queue>
#include <limits>

using namespace std;

void dijkstra(vector<vector<pair<int, int>>>& graph, int source, int destination) {
    vector<int> distances(graph.size(), numeric_limits<int>::max());
    vector<int> previous(graph.size(), -1);
    priority_queue<pair<int, int>, vector<pair<int, int>>, greater<pair<int, int>>> pq;

    distances[source] = 0;
    pq.push({0, source});

    while (!pq.empty()) {
        int u = pq.top().second;
        pq.pop();

        if (u == destination) break;

        for (auto& neighbor : graph[u]) {
            int v = neighbor.first;
            int weight = neighbor.second;

            if (distances[u] + weight < distances[v]) {
                distances[v] = distances[u] + weight;
                previous[v] = u;
                pq.push({distances[v], v});
            }
        }
    }

    if (distances[destination] == numeric_limits<int>::max()) {
        cout << "No path found.";
    } else {
        vector<int> path;
        int v = destination;
        while (v!= -1) {
            path.push_back(v);
            v = previous[v];
        }
        reverse(path.begin(), path.end());

        cout << "Shortest path: ";
        for (int node : path) {
            cout << node << " ";
        }
        cout << endl;
        cout << "Total weight: " << distances[destination] << endl;
    }
}

int main() {
    int numNodes = 5;
    vector<vector<pair<int, int>>> graph(numNodes);

    graph[0].push_back({1, 10});
    graph[0].push_back({2, 5});
    graph[1].push_back({3, 1});
    graph[2].push_back({1, 3});
    graph[2].push_back({3, 8});
    graph[2].push_back({4, 2});

    int source = 0;
    int destination = 3;

    dijkstra(graph, source, destination);

    return 0;
}

