function topologicalSort($graph) {
    $inDegree = [];
    $queue = new SplQueue();
    $result = [];

    // Initialize in-degree array
    foreach ($graph as $vertex => $neighbors) {
        if (!isset($inDegree[$vertex])) {
            $inDegree[$vertex] = 0;
        }
        foreach ($neighbors as $neighbor) {
            if (!isset($inDegree[$neighbor])) {
                $inDegree[$neighbor] = 0;
            }
            $inDegree[$neighbor]++;
        }
    }

    // Enqueue vertices with in-degree 0
    foreach ($inDegree as $vertex => $degree) {
        if ($degree === 0) {
            $queue->enqueue($vertex);
        }
    }

    // Process vertices in the queue
    while (!$queue->isEmpty()) {
        $vertex = $queue->dequeue();
        $result[] = $vertex;

        foreach ($graph[$vertex] as $neighbor) {
            $inDegree[$neighbor]--;
            if ($inDegree[$neighbor] === 0) {
                $queue->enqueue($neighbor);
            }
        }
    }

    // Check if the graph contains a cycle
    if (count($result)!== count($inDegree)) {
        throw new Exception('The graph contains a cycle.');
    }

    return $result;
}
