from collections import deque

def topological_sort(adj_list):
    in_degree = {u: 0 for u in adj_list}
    for u in adj_list:
        for v in adj_list[u]:
            in_degree[v] += 1
    queue = deque([u for u in adj_list if in_degree[u] == 0])
    top_order = []
    while queue:
        u = queue.popleft()
        top_order.append(u)
        for v in adj_list[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                queue.append(v)
    return top_order
