func main() {
	const chunkSize = 1024 * 64 // 64 KB chunks

	filePath := os.Args[1]

	file, err := os.Open(filePath)
	if err!= nil {
		fmt.Println("Error opening file:", err)
		return
	}
	defer file.Close()

	hasher := sha256.New()

	buffer := make([]byte, chunkSize)

	for {
		n, err := file.Read(buffer)
		if err!= nil {
			if err == io.EOF {
				break
			}
			fmt.Println("Error reading file:", err)
			return
		}

		_, err = hasher.Write(buffer[:n])
		if err!= nil {
			fmt.Println("Error writing to hasher:", err)
			return
		}
	}

	finalHash := hasher.Sum(nil)
	fmt.Printf("SHA-256 hash: %x\n", finalHash)
}
