class UnionFind {
  constructor(n) {
    this.id = new Array(n).fill(0).map((_, i) => i);
    this.sz = new Array(n).fill(1);
  }

  find(p) {
    while (p!== this.id[p]) {
      this.id[p] = this.id[this.id[p]];
      p = this.id[p];
    }
    return p;
  }

  union(p, q) {
    const i = this.find(p);
    const j = this.find(q);
    if (i === j) return;
    if (this.sz[i] < this.sz[j]) {
      this.id[i] = j;
      this.sz[j] += this.sz[i];
    } else {
      this.id[j] = i;
      this.sz[i] += this.sz[j];
    }
  }
}
