#include <iostream>
#include <string>
#include <vector>
#include <curl/curl.h>

struct HeaderResult {
    std::string url;
    bool xssProtection;
    bool frameOptions;
    bool contentTypeOptions;
    bool strictTransportSecurity;
    bool contentSecurityPolicy;
};

size_t writeCallback(char* buf, size_t size, size_t nmemb, void* up) {
    std::string* response = static_cast<std::string*>(up);
    response->append(buf, size * nmemb);
    return size * nmemb;
}

HeaderResult checkHeaders(const std::string& url) {
    CURL* curl = curl_easy_init();
    HeaderResult result = {url, false, false, false, false, false};

    if (curl) {
        std::string response;
        curl_easy_setopt(curl, CURLOPT_URL, url.c_str());
        curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, writeCallback);
        curl_easy_setopt(curl, CURLOPT_WRITEDATA, &response);

        CURLcode res = curl_easy_perform(curl);
        if (res == CURLE_OK) {
            curl_easy_getinfo(curl, CURLINFO_RESPONSE_CODE, &res);

            struct curl_slist* headers = NULL;
            res = curl_easy_getinfo(curl, CURLINFO_COOKIELIST, &headers);

            if (res == CURLE_OK) {
                struct curl_slist* header = headers;
                while (header) {
                    std::string headerLine = header->data;

                    if (headerLine.find("X-XSS-Protection")!= std::string::npos) {
                        result.xssProtection = true;
                    } else if (headerLine.find("X-Frame-Options")!= std::string::npos) {
                        result.frameOptions = true;
                    } else if (headerLine.find("X-Content-Type-Options")!= std::string::npos) {
                        result.contentTypeOptions = true;
                    } else if (headerLine.find("Strict-Transport-Security")!= std::string::npos) {
                        result.strictTransportSecurity = true;
                    } else if (headerLine.find("Content-Security-Policy")!= std::string::npos) {
                        result.contentSecurityPolicy = true;
                    }

                    header = header->next;
                }
            }
            curl_slist_free_all(headers);
        }
        curl_easy_cleanup(curl);
    }
    return result;
}

void printResults(const std::vector<HeaderResult>& results) {
    for (const auto& result : results) {
        std::cout << "URL: " << result.url << std::endl;
        std::cout << "  X-XSS-Protection: " << (result.xssProtection? "Present" : "Missing") << std::endl;
        std::cout << "  X-Frame-Options: " << (result.frameOptions? "Present" : "Missing") << std::endl;
        std::cout << "  X-Content-Type-Options: " << (result.contentTypeOptions? "Present" : "Missing") << std::endl;
        std::cout << "  Strict-Transport-Security: " << (result.strictTransportSecurity? "Present" : "Missing") << std::endl;
        std::cout << "  Content-Security-Policy: " << (result.contentSecurityPolicy? "Present" : "Missing") << std::endl;
        std::cout << std::endl;
    }
}

int main() {
    std::vector<std::string> targets = {
        "https://example.com",
        "https://example.org",
        "https://example.net"
    };

    std::vector<HeaderResult> results;

    for (const auto& target : targets) {
        results.push_back(checkHeaders(target));
    }

    printResults(results);

    return 0;
}

