#include <boost/asio.hpp>
#include <boost/asio/ssl.hpp>

using boost::asio::ip::tcp;

std::vector<std::string> getAlternateNames(const std::string& domain) {
    boost::asio::io_context ioContext;
    boost::asio::ssl::context sslContext(boost::asio::ssl::context::sslv23_client);

    tcp::resolver resolver(ioContext);
    tcp::resolver::query query(domain, "443");
    tcp::resolver::iterator endpointIterator = resolver.resolve(query);

    boost::asio::ssl::stream<tcp::socket> socket(ioContext, sslContext);
    boost::asio::connect(socket.lowest_layer(), endpointIterator);
    socket.handshake(boost::asio::ssl::stream_base::client);

    boost::asio::ssl::stream<tcp::socket>::lowest_layer_type& lowestLayer = socket.lowest_layer();
    lowestLayer.shutdown(tcp::socket::shutdown_both);

    boost::system::error_code ec;
    lowestLayer.close(ec);

    auto cert = socket.native_handle()->session->peer;
    auto san = cert->extensions[X509_EXT_SUBJECT_ALT_NAME].get_value<string>();

    std::istringstream iss(san);
    std::vector<std::string> alternateNames;
    std::string name;
    while (std::getline(iss, name, ',')) {
        alternateNames.push_back(name);
    }

    return alternateNames;
}

int main(int argc, char* argv[]) {
    if (argc!= 2) {
        std::cerr << "Usage: " << argv[0] << " <domain>" << std::endl;
        return 1;
    }

    std::string domain(argv[1]);
    std::vector<std::string> alternateNames = getAlternateNames(domain);

    std::cout << "Alternate names for " << domain << ":" << std::endl;
    for (const auto& name : alternateNames) {
        std::cout << "- " << name << std::endl;
    }

    return 0;
}

