// Command is the interface for the command.
type Command interface {
    Execute()
}

// ConcreteCommand is a concrete implementation of the Command interface.
// It holds a reference to the Receiver object and implements the Execute method.
// The Execute method invokes the appropriate action on the Receiver.
type ConcreteCommand struct {
    receiver *Receiver
}

func (c *ConcreteCommand) Execute() {
    c.receiver.Action()
}

// Receiver is the object that performs the actual work when the command's Execute method is called.
// It defines the action that the command should perform.
type Receiver struct {}

func (r *Receiver) Action() {
    fmt.Println("Receiver: Performing the requested action.")
}

// Invoker holds a reference to a Command object and is responsible for invoking the command.
// It doesn't know the specific command being executed or the receiver associated with it.
type Invoker struct {
    command Command
}

func (i *Invoker) SetCommand(command Command) {
    i.command = command
}

func (i *Invoker) Invoke() {
    i.command.Execute()
}

func main() {
    // Create the receiver object
    receiver := &Receiver{}

    // Create the concrete command and pass the receiver to it
    concreteCommand := &ConcreteCommand{receiver: receiver}

    // Create the invoker and set the command
    invoker := &Invoker{}
    invoker.SetCommand(concreteCommand)

    // Invoke the command using the invoker
    fmt.Println("Invoker: Invoking the command.")
    invoker.Invoke()
}
