from typing import List

class Subject:
    def __init__(self):
        self._observers: List[Observer] = []

    def attach(self, observer: Observer):
        self._observers.append(observer)

    def detach(self, observer: Observer):
        self._observers.remove(observer)

    def notify(self):
        for observer in self._observers:
            observer.update(self)

class WeatherData(Subject):
    def __init__(self):
        super().__init__()
        self.temperature: float = 0.0
        self.humidity: float = 0.0
        self.pressure: float = 0.0

    def set_measurements(self, temperature: float, humidity: float, pressure: float):
        self.temperature = temperature
        self.humidity = humidity
        self.pressure = pressure
        self.notify()

class Observer:
    def update(self, subject: Subject):
        pass

class CurrentConditionsDisplay(Observer):
    def __init__(self, weather_data: WeatherData):
        self.weather_data = weather_data
        self.weather_data.attach(self)

    def update(self, subject: Subject):
        if subject is self.weather_data:
            print(f"Current conditions: {self.weather_data.temperature}°C, {self.weather_data.humidity}% humidity")

class ForecastDisplay(Observer):
    def __init__(self, weather_data: WeatherData):
        self.weather_data = weather_data
        self.weather_data.attach(self)

    def update(self, subject: Subject):
        if subject is self.weather_data:
            print("Forecast: Improving weather on the way!")

class StatisticsDisplay(Observer):
    def __init__(self, weather_data: WeatherData):
        self.weather_data = weather_data
        self.weather_data.attach(self)

    def update(self, subject: Subject):
        if subject is self.weather_data:
            print(f"Statistics: Temperature - {self.weather_data.temperature}°C, Humidity - {self.weather_data.humidity}%")

# Usage example
weather_data = WeatherData()
current_display = CurrentConditionsDisplay(weather_data)
forecast_display = ForecastDisplay(weather_data)
statistics_display = StatisticsDisplay(weather_data)

weather_data.set_measurements(26.5, 65.0, 1013.1)
weather_data.set_measurements(27.2, 62.5, 1014.2)
