func getPermutations(str string) []string {
    var helper func([]byte, int)
    var result []string

    helper = func(arr []byte, n int) {
        if n == 1 {
            result = append(result, string(arr))
            return
        }

        for i := 0; i < n; i++ {
            helper(arr, n-1)
            if n%2 == 1 {
                arr[0], arr[n-1] = arr[n-1], arr[0]
            } else {
                arr[i], arr[n-1] = arr[n-1], arr[i]
            }
        }
    }

    helper([]byte(str), len(str))
    return result
