std::string runLengthDecode(const std::string& input) {
    std::stringstream decoded;
    std::stringstream countStream;
    char prevChar = '\0';

    for (char c : input) {
        if (isdigit(c)) {
            countStream << c;
        } else {
            if (prevChar!= '\0') {
                int count = std::stoi(countStream.str());
                for (int i = 0; i < count; i++) {
                    decoded << prevChar;
                }
                countStream.str("");
            }
            prevChar = c;
        }
    }

    if (prevChar!= '\0') {
        int count = std::stoi(countStream.str());
        for (int i = 0; i < count; i++) {
            decoded << prevChar;
        }
    }

