#include <stdio.h>
#include <stdlib.h>

#define MAX_NODES 100

int graph[MAX_NODES][MAX_NODES];
int visited[MAX_NODES];
int topo_order[MAX_NODES];
int topo_index = 0;

void dfs(int node, int n) {
    visited[node] = 1;
    for (int i = 0; i < n; i++) {
        if (graph[node][i] &&!visited[i]) {
            dfs(i, n);
        }
    }
    topo_order[topo_index++] = node;
}

void topological_sort(int n) {
    for (int i = 0; i < n; i++) {
        visited[i] = 0;
    }
    topo_index = 0;
    for (int i = 0; i < n; i++) {
        if (!visited[i]) {
            dfs(i, n);
        }
    }
    for (int i = n - 1; i >= 0; i--) {
        printf("%d ", topo_order[i]);
    }
}

