#include <iostream>
#include <fstream>
#include <string>
#include <vector>
#include <thread>
#include <mutex>
#include <condition_variable>
#include <sys/socket.h>
#include <arpa/inet.h>

std::vector<std::string> read_domains_from_file(const std::string& filename) {
    std::vector<std::string> domains;
    std::ifstream file(filename);
    std::string line;
    while (std::getline(file, line)) {
        domains.push_back(line);
    }
    return domains;
}

void resolve_and_probe(const std::string& domain, std::mutex& mtx, std::condition_variable& cv, int& count, const int& total) {
    struct sockaddr_in addr{};
    if (inet_pton(AF_INET, domain.c_str(), &addr.sin_addr)!= 1) {
        std::unique_lock<std::mutex> lock(mtx);
        std::cout << "Failed to resolve domain: " << domain << std::endl;
        count++;
        cv.notify_one();
        return;
    }

    int sock = socket(AF_INET, SOCK_STREAM, 0);
    if (sock == -1) {
        std::unique_lock<std::mutex> lock(mtx);
        std::cout << "Failed to create socket for domain: " << domain << std::endl;
        count++;
        cv.notify_one();
        return;
    }

    if (connect(sock, (struct sockaddr*)&addr, sizeof(addr)) == -1) {
        std::unique_lock<std::mutex> lock(mtx);
        std::cout << "Domain " << domain << " is not reachable" << std::endl;
    } else {
        std::unique_lock<std::mutex> lock(mtx);
        std::cout << "Domain " << domain << " is reachable" << std::endl;
    }
    close(sock);
    count++;
    cv.notify_one();
}

int main() {
    std::string filename = "domains.txt";
    std::vector<std::string> domains = read_domains_from_file(filename);
    int total = domains.size();
    int count = 0;
    std::mutex mtx;
    std::condition_variable cv;

    for (const std::string& domain : domains) {
        std::thread t(resolve_and_probe, domain, std::ref(mtx), std::ref(cv), std::ref(count), std::ref(total));
        t.detach();
    }

    std::unique_lock<std::mutex> lock(mtx);
    cv.wait(lock, [&] { return count == total; });

    return 0;
}

