            with open(file_path, 'rb') as f:
                content = f.read()
                hash_value = hashlib.sha256(content).hexdigest()
                if hash_value in hashes:
                    hashes[hash_value].append(file_path)
                else:
                    hashes[hash_value] = [file_path]
    return hashes

def main():
    parser = argparse.ArgumentParser(description='Find duplicate files by hashing their contents.')
    parser.add_argument('directory', type=str, help='Directory to search for duplicate files')
    args = parser.parse_args()

    duplicate_files = find_duplicate_files(args.directory)
    for hash_value, files in duplicate_files.items():
        if len(files) > 1:
            print(f'Duplicate files with hash {hash_value}:')
            for file in files:
                print(file)
            print()

if __name__ == '__main__':
    main()
