package main

import (
    "fmt"
)

type Node struct {
    data int
    prev *Node
    next *Node
}

type DoublyLinkedList struct {
    head *Node
    tail *Node
}

func (dll *DoublyLinkedList) InsertAtBeginning(data int) {
    newNode := &Node{data, nil, nil}
    if dll.head == nil {
        dll.head = newNode
        dll.tail = newNode
    } else {
        newNode.next = dll.head
        dll.head.prev = newNode
        dll.head = newNode
    }
}

func (dll *DoublyLinkedList) DeleteByValue(data int) {
    if dll.head == nil {
        return
    }
    current := dll.head
    for current!= nil {
        if current.data == data {
            if current.prev!= nil {
                current.prev.next = current.next
            } else {
                dll.head = current.next
            }
            if current.next!= nil {
                current.next.prev = current.prev
            } else {
                dll.tail = current.prev
            }
            break
        }
        current = current.next
    }
}

func (dll *DoublyLinkedList) Reverse() {
    if dll.head == nil {
        return
    }
    current := dll.head
    var prev *Node = nil
    dll.tail = dll.head
    for current!= nil {
        next := current.next
        current.next = prev
        current.prev = next
        prev = current
        current = next
    }
    dll.head = prev
}

func (dll *DoublyLinkedList) PrintList() {
    current := dll.head
    for current!= nil {
        fmt.Printf("%d ", current.data)
        current = current.next
    }
    fmt.Println()
}

func main() {
    dll := &DoublyLinkedList{}
    dll.InsertAtBeginning(1)
    dll.InsertAtBeginning(2)
    dll.InsertAtBeginning(3)
    dll.InsertAtBeginning(4)
    fmt.Println("Original list:")
    dll.PrintList()
    dll.DeleteByValue(3)
    fmt.Println("List after deleting 3:")
    dll.PrintList()
    dll.Reverse()
    fmt.Println("Reversed list:")
    dll.PrintList()
}
