import time

class ExponentialBackoffIterator:
    def __init__(self, max_retries, scale_factor):
        self.max_retries = max_retries
        self.scale_factor = scale_factor
        self.retries = 0
        self.delay = 1

    def __iter__(self):
        return self

    def __next__(self):
        if self.retries >= self.max_retries:
            raise StopIteration

        try:
            # Perform iteration logic here
            # For example, fetching data from an unreliable source
            data = self.fetch_data()
            return data
        except Exception as e:
            if self.retries < self.max_retries:
                time.sleep(self.delay)
                self.delay *= self.scale_factor
                self.retries += 1
                return self.__next__()
            else:
                raise e

class DataFetcher(ExponentialBackoffIterator):
    def fetch_data(self):
        # Simulating an unreliable data source
        if self.retries < 3:
            raise Exception("Failed to fetch data")
        return "Data fetched successfully"
