use actix_web::{web, HttpResponse, HttpRequest, Responder};
use jsonwebtoken::{encode, decode, Header, Algorithm, Validation};
use serde::{Serialize, Deserialize};
use std::time::{SystemTime, UNIX_EPOCH};

#[derive(Debug, Serialize, Deserialize)]
struct Claims {
    sub: String,
    exp: u64,
}

const SECRET_KEY: &[u8] = b"secret_key_for_signing_tokens";

fn create_token(user_id: &str) -> String {
    let expiration = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs() + 3600; // 1 hour
    let claims = Claims {
        sub: user_id.to_string(),
        exp: expiration,
    };
    encode(&Header::new(Algorithm::HS256), &claims, SECRET_KEY).unwrap()
}

fn verify_token(token: &str) -> Result<String, jsonwebtoken::errors::Error> {
    let validation = Validation::new(Algorithm::HS256);
    let token_data = decode::<Claims>(token, SECRET_KEY, &validation)?;
    Ok(token_data.claims.sub)
}

async fn login(req: HttpRequest, user_id: web::Path<String>) -> impl Responder {
    let token = create_token(&user_id);
    HttpResponse::Ok()
       .cookie(
            actix_web::cookie::Cookie::build("session", token)
               .path("/")
               .secure(true)
               .http_only(true)
               .same_site(actix_web::cookie::SameSite::Strict)
               .finish(),
        )
       .body("Logged in")
}

async fn protected_route(req: HttpRequest) -> impl Responder {
    let cookie = req.cookie("session");
    match cookie {
        Some(session_cookie) => {
            match verify_token(session_cookie.value()) {
                Ok(user_id) => HttpResponse::Ok().body(format!("Welcome, {}", user_id)),
