import time
from threading import RLock

class CacheItem:
    def __init__(self, value, ttl):
        self.value = value
        self.expiry_time = time.time() + ttl

    def is_expired(self):
        return time.time() > self.expiry_time

class CachedIterator:
    def __init__(self, iterable, ttl=60):
        self.iterable = iterable
        self.ttl = ttl
        self.cache = {}
        self.lock = RLock()
        self.position = 0

    def __iter__(self):
        return self

    def __next__(self):
        with self.lock:
            if self.position in self.cache:
                cache_item = self.cache[self.position]
                if not cache_item.is_expired():
                    self.position += 1
                    return cache_item.value
                else:
                    del self.cache[self.position]
            try:
                value = next(self.iterable)
                self.cache[self.position] = CacheItem(value, self.ttl)
                self.position += 1
                return value
            except StopIteration:
                raise
