use std::collections::HashMap;
use std::time::{Duration, Instant};

struct Entry<V> {
    value: V,
    expires_at: Option<Instant>,
}

impl<V> Entry<V> {
    fn is_expired(&self) -> bool {
        self.expires_at.map_or(false, |expires_at| Instant::now() >= expires_at)
    }
}

pub struct KvStore<V> {
    map: HashMap<String, Entry<V>>,
}

impl<V> KvStore<V> {
    pub fn new() -> Self {
        KvStore {
            map: HashMap::new(),
        }
    }

    pub fn insert(&mut self, key: String, value: V, expires_after: Option<Duration>) {
        let expires_at = expires_after.map(|duration| Instant::now() + duration);
        self.map.insert(key, Entry { value, expires_at });
    }

    pub fn get(&mut self, key: &str) -> Option<&V> {
        self.map.get(key).filter(|entry|!entry.is_expired()).map(|entry| &entry.value)
    }

    pub fn contains_key(&mut self, key: &str) -> bool {
        self.map.get(key).map_or(false, |entry|!entry.is_expired())
    }
}
