package main

import (
	"crypto/hmac"
	"crypto/sha1"
	"encoding/base32"
	"fmt"
	"math"
	"strings"
	"time"
)

func generateSecretKey(length int) string {
	secret := make([]byte, length)
	_, err := rand.Read(secret)
	if err!= nil {
		panic(err)
	}
	return base32.StdEncoding.EncodeToString(secret)
}

func generateTOTP(secret string, timestamp int64) string {
	secretBytes, err := base32.StdEncoding.DecodeString(strings.ToUpper(secret))
	if err!= nil {
		panic(err)
	}

	timestamp /= 30
	tsBytes := make([]byte, 8)
	for i := 7; i >= 0; i-- {
		tsBytes[i] = byte(timestamp & 0xff)
		timestamp >>= 8
	}

	hmac := hmac.New(sha1.New, secretBytes)
	_, err = hmac.Write(tsBytes)
	if err!= nil {
		panic(err)
	}
	hash := hmac.Sum(nil)

	offset := hash[len(hash)-1] & 0xf
	binary := ((uint32(hash[offset]) & 0x7f) << 24) |
		((uint32(hash[offset+1]) & 0xff) << 16) |
		((uint32(hash[offset+2]) & 0xff) << 8) |
		(uint32(hash[offset+3]) & 0xff)

	digits := uint32(6)
	code := uint32(binary % int(math.Pow10(int(digits))))
	return fmt.Sprintf("%%0%dd", code)
}

func verifyTOTP(secret, userCode string) bool {
	currentTime := time.Now().Unix()
	generatedCode := generateTOTP(secret, currentTime)
	return generatedCode == userCode
}

func main() {
	secret := generateSecretKey(10)
	fmt.Println("Secret Key:", secret)

	currentTime := time.Now().Unix()
	generatedCode := generateTOTP(secret, currentTime)
	fmt.Println("Generated TOTP Code:", generatedCode)

	userCode := "123456" // Replace with user-provided code
	isValid := verifyTOTP(secret, userCode)
	fmt.Println("Is TOTP Code Valid?:", isValid)
}
