package main

import (
    "fmt"
)

type Graph struct {
    vertices int
    adjList  map[int][]int
}

func newGraph(vertices int) *Graph {
    return &Graph{vertices, make(map[int][]int)}
}

func (g *Graph) addEdge(src, dest int) {
    g.adjList[src] = append(g.adjList[src], dest)
}

func topologicalSort(g *Graph) []int {
    visited := make([]bool, g.vertices)
    stack := make([]int, 0)

    for i := 0; i < g.vertices; i++ {
        if!visited[i] {
            topologicalSortUtil(i, visited, stack, g)
        }
    }

    return stack
}

func topologicalSortUtil(v int, visited []bool, stack []int, g *Graph) {
    visited[v] = true

    for _, neighbor := range g.adjList[v] {
        if!visited[neighbor] {
            topologicalSortUtil(neighbor, visited, stack, g)
        }
    }

    stack = append(stack, v)
}

func main() {
    g := newGraph(6)
    g.addEdge(5, 2)
    g.addEdge(5, 0)
    g.addEdge(4, 0)
    g.addEdge(4, 1)
    g.addEdge(2, 3)
    g.addEdge(3, 1)

    result := topologicalSort(g)
    fmt.Println("Topological order:", result)
