}

fn main() {
    let urls = vec![
        "https://api.example.com/endpoint1",
        "https://api.example.com/endpoint2",
        // Add more URLs as needed
    ];
    let concurrency_limit = 5;

    let client = Client::new();
    let active_requests = Arc::new(Mutex::new(0));
    let results = Arc::new(Mutex::new(Vec::new()));

    let handles: Vec<_> = urls.into_iter().map(|url| {
        let client = client.clone();
        let active_requests = Arc::clone(&active_requests);
        let results = Arc::clone(&results);

        thread::spawn(move || {
            loop {
                let mut num_active_requests = active_requests.lock().unwrap();
                if *num_active_requests < concurrency_limit {
                    *num_active_requests += 1;
                    drop(num_active_requests);
                    break;
                }
                drop(num_active_requests);
                thread::yield_now();
            }

            let result = tokio::runtime::Runtime::new().unwrap().block_on(fetch_url(&client, &url));

            let mut results = results.lock().unwrap();
            results.push((url, result));

            let mut num_active_requests = active_requests.lock().unwrap();
            *num_active_requests -= 1;
        })
    }).collect();

    for handle in handles {
        handle.join().unwrap();
    }

    let results = Arc::try_unwrap(results).unwrap().into_inner().unwrap();
    for (url, result) in results {
        match result {
            Ok((status, body)) => println!("{}: {} - {}", url, status, body),
