import time
import functools
import hashlib
import json

def cache_with_ttl(ttl=None):
    def decorator(func):
        cache = {}

        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            key = json.dumps((args, str(kwargs)))
            hash_key = hashlib.sha256(key.encode()).hexdigest()

            if hash_key in cache:
                result, expiry = cache[hash_key]
                if ttl is None or time.time() < expiry:
                    return result
                else:
                    del cache[hash_key]

            result = func(*args, **kwargs)
            cache[hash_key] = (result, time.time() + ttl) if ttl else (result, None)
            return result

        def clear_cache():
            nonlocal cache
            cache = {}

        wrapper.clear_cache = clear_cache
        return wrapper

    return decorator
