trait Observer<T> {
    fn update(&self, data: &T);
}

trait Subject<T> {
    fn register_observer(&mut self, observer: Box<dyn Observer<T>>);
    fn remove_observer(&mut self, observer: &Box<dyn Observer<T>>);
    fn notify_observers(&self);
}

struct DataSubject<T> {
    observers: Vec<Box<dyn Observer<T>>>,
    data: T,
}

impl<T: Clone> Subject<T> for DataSubject<T> {
    fn register_observer(&mut self, observer: Box<dyn Observer<T>>) {
        self.observers.push(observer);
    }

    fn remove_observer(&mut self, observer: &Box<dyn Observer<T>>) {
        if let Some(index) = self.observers.iter().position(|x| *x == **observer) {
            self.observers.remove(index);
        }
    }

    fn notify_observers(&self) {
        for observer in &self.observers {
            observer.update(&self.data);
        }
    }
}

impl<T> DataSubject<T> {
    fn new(data: T) -> Self {
        DataSubject {
            observers: Vec::new(),
            data,
        }
    }

    fn set_data(&mut self, data: T) {
        self.data = data;
        self.notify_observers();
    }
}

struct DataObserver;

impl<T: std::fmt::Display> Observer<T> for DataObserver {
    fn update(&self, data: &T) {
        println!("Observer notified: {}", data);
    }
}

fn main() {
    let mut subject = DataSubject::new(0);
    let observer = Box::new(DataObserver);

    subject.register_observer(observer);
    subject.set_data(10);
    subject.set_data(20);
}
