def monitor_dns_changes(domain, interval=60):
    previous_records = get_dns_records(domain)
    while True:
        time.sleep(interval)
        current_records = get_dns_records(domain)
        if current_records!= previous_records:
            print(f'DNS records changed for {domain}')
            for record_type in current_records:
                previous_data = previous_records[record_type]
                current_data = current_records[record_type]
                if previous_data!= current_data:
                    print(f'{record_type} records:')
                    for line in difflib.unified_diff(previous_data, current_data, lineterm=''):                        print(line)
