fn run_length_encode(input: &str) -> String {
    let mut encoded = String::new();
    let mut count = 1;
    let mut prev_char = input.chars().next().unwrap();

    for c in input.chars().skip(1) {
        if c == prev_char {
            count += 1;
        } else {
            encoded.push_str(&format!("{}{}", count, prev_char));
            prev_char = c;
            count = 1;
        }
    }
    encoded.push_str(&format!("{}{}", count, prev_char));
    encoded
}

fn run_length_decode(input: &str) -> String {
    let mut decoded = String::new();
    let mut count_str = String::new();

    for c in input.chars() {
        if c.is_numeric() {
            count_str.push(c);
        } else {
            let count: usize = count_str.parse().unwrap();
            decoded.push_str(&c.to_string().repeat(count));
            count_str.clear();
        }
    }
    decoded
}
