import threading
import queue
import time

class Worker(threading.Thread):
    def __init__(self, job_queue):
        super().__init__()
        self.job_queue = job_queue
        self.daemon = True

    def run(self):
        while True:
            job = self.job_queue.get()
            if job is None:
                break
            job()
            self.job_queue.task_done()

class ThreadPool:
    def __init__(self, num_workers):
        self.job_queue = queue.Queue()
        self.workers = [Worker(self.job_queue) for _ in range(num_workers)]

    def start(self):
        for worker in self.workers:
            worker.start()

    def submit(self, job):
        self.job_queue.put(job)

    def shutdown(self):
        for _ in self.workers:
            self.job_queue.put(None)
        for worker in self.workers:
            worker.join()

# Example usage

def my_job():
    print('Executing job...')
    time.sleep(1)

pool = ThreadPool(num_workers=3)
pool.start()

for _ in range(10):
    pool.submit(my_job)

pool.shutdown()
