#include <stdio.h>
#include <stdlib.h>

#define MAX_SIZE 100

int parent[MAX_SIZE];
int size[MAX_SIZE];

void init(int n) {
    for (int i = 0; i < n; i++) {
        parent[i] = i;
        size[i] = 1;
    }
}

int find(int x) {
    if (parent[x]!= x) {
        parent[x] = find(parent[x]);
    }
    return parent[x];
}

void unite(int x, int y) {
    int rootX = find(x);
    int rootY = find(y);
    if (rootX!= rootY) {
        if (size[rootX] < size[rootY]) {
            parent[rootX] = rootY;
            size[rootY] += size[rootX];
        } else {
            parent[rootY] = rootX;
            size[rootX] += size[rootY];
        }
    }
}

int main() {
    int n = 5;
    init(n);
    unite(0, 1);
    unite(1, 2);
    unite(3, 4);
    printf("Find 0: %d\n", find(0));
    printf("Find 1: %d\n", find(1));
    printf("Find 2: %d\n", find(2));
    printf("Find 3: %d\n", find(3));
    printf("Find 4: %d\n", find(4));
    return 0;
