import argparse
import json
import yaml
import toml

def parse_arguments():
    parser = argparse.ArgumentParser(description='File format converter (JSON, YAML, TOML)')
    parser.add_argument('input_file', help='Path to the input file')
    parser.add_argument('output_format', choices=['json', 'yaml', 'toml'], help='Output format')
    return parser.parse_args()

def load_file(file_path):
    with open(file_path, 'r') as file:
        if file_path.endswith('.json'):
            return json.load(file)
        elif file_path.endswith('.yaml') or file_path.endswith('.yml'):
            return yaml.safe_load(file)
        elif file_path.endswith('.toml'):
            return toml.load(file)
        else:
            raise ValueError('Unsupported file format')

def convert_data(data, output_format):
    if output_format == 'json':
        return json.dumps(data, indent=2)
    elif output_format == 'yaml':
        return yaml.dump(data, indent=2)
    elif output_format == 'toml':
        return toml.dumps(data)
    else:
        raise ValueError('Unsupported output format')

def main():
    args = parse_arguments()
    try:
        data = load_file(args.input_file)
        converted_data = convert_data(data, args.output_format)
        print(converted_data)
    except (FileNotFoundError, ValueError) as e:
        print(f'Error: {str(e)}')

if __name__ == '__main__':
    main()
