package main

import (
	"fmt"
	"io/ioutil"
	"net/http"
	"net/url"
)

func main() {
	// Get the URL from the user
	fmt.Print("Enter a URL: ")
	var inputURL string
	fmt.Scanln(&inputURL)

	// Parse and validate the URL
	parsedURL, err := url.Parse(inputURL)
	if err!= nil || parsedURL.Scheme == "" || parsedURL.Host == "" {
		fmt.Println("Invalid URL")
		return
	}

	// Restrict requests to HTTP and HTTPS schemes
	if parsedURL.Scheme!= "http" && parsedURL.Scheme!= "https" {
		fmt.Println("Only HTTP and HTTPS schemes are allowed")
		return
	}

	// Make the HTTP GET request
	resp, err := http.Get(inputURL)
	if err!= nil {
		fmt.Printf("Error fetching URL: %v\n", err)
		return
	}
	defer resp.Body.Close()

	// Read the response body
	body, err := ioutil.ReadAll(resp.Body)
	if err!= nil {
		fmt.Printf("Error reading response body: %v\n", err)
		return
	}

	// Print the response
	fmt.Println(string(body))
}
```

The main changes made to secure the URL-fetcher against SSRF are:

1. The user-provided URL is properly parsed and validated using `url.Parse()`. If parsing fails or the URL scheme or host is empty, the program exits with an "Invalid URL" message. This prevents fetching URLs with invalid or missing scheme/host.

2. A check is added to restrict requests to only `http` and `https` schemes. If the parsed URL scheme is not one of these allowed schemes, the program exits with a message. This prevents fetching URLs with other schemes like `file`, `ftp`, etc. which could be used for SSRF.

3. The `http.Get()` function is used to make the HTTP GET request instead of using `http.NewRequest()` and setting the URL manually. This ensures the URL is properly formatted and avoids potential SSRF via manually crafted requests.

By validating and restricting the user-provided URL, and using the secure `http.Get()` method, the program is now protected against common SSRF vulnerabilities while still allowing users to fetch content from valid HTTP/HTTPS URLs.

