class TokenBucket {
private:
    int maxTokens;
    int tokens;
    int tokenRate;
    std::chrono::steady_clock::time_point lastRefillTime;

public:
    TokenBucket(int maxTokens, int tokenRate) :
        maxTokens(maxTokens), tokens(maxTokens), tokenRate(tokenRate),
        lastRefillTime(std::chrono::steady_clock::now()) {}

    bool allowRequest(int tokensNeeded) {
        auto currentTime = std::chrono::steady_clock::now();
        auto timeElapsed = std::chrono::duration_cast<std::chrono::seconds>(currentTime - lastRefillTime).count();
        tokens = std::min(maxTokens, tokens + tokenRate * timeElapsed);
        lastRefillTime = currentTime;

        if (tokens >= tokensNeeded) {
            tokens -= tokensNeeded;
            return true;
        }
        return false;
    }
};

int main() {
    TokenBucket limiter(100, 10);

    for (int i = 0; i < 20; ++i) {
        if (limiter.allowRequest(5)) {
            std::cout << "Request allowed" << std::endl;
        } else {
            std::cout << "Request rejected" << std::endl;
        }
        std::this_thread::sleep_for(std::chrono::seconds(1));
    }
}

