function levenshteinDistance($str1, $str2) {
    $m = strlen($str1);
    $n = strlen($str2);

    if ($m == 0) {
        return $n;
    }

    if ($n == 0) {
        return $m;
    }

    $matrix = array_fill(0, $m + 1, array_fill(0, $n + 1, 0));

    for ($i = 1; $i <= $m; $i++) {
        $matrix[$i][0] = $i;
    }

    for ($j = 1; $j <= $n; $j++) {
        $matrix[0][$j] = $j;
    }

    for ($i = 1; $i <= $m; $i++) {
        for ($j = 1; $j <= $n; $j++) {
            if ($str1[$i - 1] == $str2[$j - 1]) {
                $matrix[$i][$j] = $matrix[$i - 1][$j - 1];
            } else {
                $matrix[$i][$j] = min(
                    $matrix[$i - 1][$j] + 1,
                    $matrix[$i][$j - 1] + 1,
                    $matrix[$i - 1][$j - 1] + 1
                );
            }
        }
    }

    return $matrix[$m][$n];
}
