struct ListNode<T> {
    val: T,
    next: Option<Box<ListNode<T>>>,
}

use std::cmp::Ordering;
use std::collections::BinaryHeap;

struct MinHeap<T>(BinaryHeap<T>);
implement<T: Ord> MinHeap<T> {
    fn new() -> Self {
        MinHeap(BinaryHeap::new())
    }

    fn push(&mut self, item: T) {
        self.0.push(item)
    }

    fn pop(&mut self) -> Option<T> {
        self.0.pop()
    }

    fn len(&self) -> usize {
        self.0.len()
    }
}

impl<T: Ord> Iterator for MinHeap<T> {
    type Item = T;

    fn next(&mut self) -> Option<Self::Item> {
        self.pop()
    }
}

fn merge_k_lists<T: Ord>(lists: Vec<Option<Box<ListNode<T>>>>) -> Option<Box<ListNode<T>>> {
    let mut heap = MinHeap::new();

    for list in lists {
        if let Some(node) = list {
            heap.push(node);
        }
    }

    let mut dummy = ListNode {
        val: std::marker::PhantomData,
        next: None,
    };
    let mut tail = &mut dummy;

    while let Some(mut node) = heap.pop() {
        if let Some(next) = node.next.take() {
            heap.push(next);
        }
        tail.next = Some(node);
        tail = tail.next.as_mut().unwrap();
    }

    dummy.next
}
