#include <chrono>
#include <functional>
#include <random>

// Retry with exponential backoff and jitter
//
// fn: The function to retry
// max_retries: The maximum number of retries before giving up
// base_delay: The base delay in milliseconds
// jitter_factor: The jitter factor (between 0 and 1)
//
// Returns the result of the function if successful, or throws an exception if all retries fail
template <typename Fn>
auto retry_with_backoff(Fn fn, int max_retries, int base_delay, double jitter_factor) {
    std::random_device rd;
    std::mt19937 gen(rd());
    std::uniform_real_distribution<> dis(1 - jitter_factor, 1 + jitter_factor);

    int delay = base_delay;
    for (int attempt = 1; attempt <= max_retries; ++attempt) {
        try {
            return fn();
        } catch (...) {
            if (attempt == max_retries) {
                throw;
            }
            int jittered_delay = static_cast<int>(delay * dis(gen));
            std::this_thread::sleep_for(std::chrono::milliseconds(jittered_delay));
            delay *= 2;
        }
    }
}
