import time
from threading import Lock, Thread

class TokenBucket:
    def __init__(self, rate, capacity):
        self.rate = rate  # tokens per second
        self.capacity = capacity  # maximum token capacity
        self.tokens = capacity  # initial number of tokens
        self.last_refill = time.time()
        self.lock = Lock()

    def refill_tokens(self):
        now = time.time()
        elapsed = now - self.last_refill
        new_tokens = elapsed * self.rate
        if new_tokens > 0:
            self.tokens = min(self.capacity, self.tokens + new_tokens)
            self.last_refill = now

    def consume_token(self):
        with self.lock:
            self.refill_tokens()
            if self.tokens > 0:
                self.tokens -= 1
                return True
            return False

    def request(self):
        while not self.consume_token():
            time.sleep(1 / self.rate)
        print("Request processed")

def test_rate_limiter(rate, capacity, num_requests, interval):
    bucket = TokenBucket(rate, capacity)
    threads = [
        Thread(target=bucket.request)
        for _ in range(num_requests)
    ]
    start = time.time()
    for thread in threads:
        thread.start()
        time.sleep(interval)
    for thread in threads:
        thread.join()
    end = time.time()
    print(f"Processed {num_requests} requests in {end - start:.2f} seconds")

