std::vector<uint8_t> compressDirectoryToMemory(const std::string& directoryPath) {
    int error = 0;
    zip_t* zip = zip_open("", ZIP_CREATE, &error);
    if (!zip) {
        throw std::runtime_error("Failed to create in-memory ZIP.");
    }

    for (const auto& entry : std::filesystem::recursive_directory_iterator(directoryPath)) {
        if (entry.is_regular_file()) {
            std::string filePath = entry.path().string();
            std::string zipPath = std::filesystem::relative(entry.path(), directoryPath).string();
            zip_source_t* source = zip_source_file(zip, filePath.c_str(), 0, 0);
            int res = zip_add(zip, zipPath.c_str(), source);
            if (res < 0) {
                zip_source_free(source);
                throw std::runtime_error("Failed to add file to ZIP.");
            }
        }
    }

    size_t zipSize = 0;
    int res = zip_get_archive_size(zip, &zipSize);
    if (res < 0) {
        throw std::runtime_error("Failed to get ZIP size.");
    }

    std::vector<uint8_t> zipData(zipSize);
    res = zip_read_zip(zip, zipData.data(), zipSize);
    if (res < 0) {
        throw std::runtime_error("Failed to read ZIP data.");
    }

    zip_discard(zip);
    return zipData;
}

