```java
import java.util.*;

class Node {
    int x, y;
    double g, h, f;
    Node parent;

    public Node(int x, int y) {
        this.x = x;
        this.y = y;
    }
}

class AStar {
    private static final int DIAGONAL_COST = 14;
    private static final int V_H_COST = 10;

    public static List<Node> findPath(Node startNode, Node goalNode, Node[][] grid) {
        PriorityQueue<Node> openList = new PriorityQueue<>(Comparator.comparingDouble(n -> n.f));
        Set<Node> closedList = new HashSet<>();

        startNode.g = 0;
        startNode.h = calculateHeuristic(startNode, goalNode);
        startNode.f = startNode.g + startNode.h;
        startNode.parent = null;

        openList.add(startNode);

        while (!openList.isEmpty()) {
            Node current = openList.poll();
            closedList.add(current);

            if (current.x == goalNode.x && current.y == goalNode.y) {
                return buildPath(goalNode);
            }

            for (Node neighbor : getNeighbors(current, grid)) {
                if (closedList.contains(neighbor)) continue;

                double tentativeG = current.g + calculateDistance(current, neighbor);

                if (!openList.contains(neighbor) || tentativeG < neighbor.g) {
                    neighbor.g = tentativeG;
                    neighbor.h = calculateHeuristic(neighbor, goalNode);
                    neighbor.f = neighbor.g + neighbor.h;
                    neighbor.parent = current;

                    if (!openList.contains(neighbor)) {
                        openList.add(neighbor);
                    }
                }
            }
        }

        return null; // No path found
    }

    private static List<Node> buildPath(Node node) {
        List<Node> path = new ArrayList<>();
        while (node!= null) {
            path.add(node);
            node = node.parent;
        }
        Collections.reverse(path);
        return path;
    }

    private static double calculateHeuristic(Node node1, Node node2) {
        return Math.abs(node1.x - node2.x) + Math.abs(node1.y - node2.y);
    }

    private static double calculateDistance(Node node1, Node node2) {
        int xDiff = Math.abs(node1.x - node2.x);
        int yDiff = Math.abs(node1.y - node2.y);
        return xDiff > yDiff? DIAGONAL_COST * yDiff + V_H_COST * (xDiff - yDiff) : DIAGONAL_COST * xDiff + V_H_COST * (yDiff - xDiff);
    }

    private static List<Node> getNeighbors(Node node, Node[][] grid) {
        int x = node.x;
        int y = node.y;
        List<Node> neighbors = new ArrayList<>();

        if (isValid(x - 1, y, grid)) neighbors.add(grid[x - 1][y]); // Left
        if (isValid(x + 1, y, grid)) neighbors.add(grid[x + 1][y]); // Right
        if (isValid(x, y - 1, grid)) neighbors.add(grid[x][y - 1]); // Top
        if (isValid(x, y + 1, grid)) neighbors.add(grid[x][y + 1]); // Bottom

        return neighbors;
    }

    private static boolean isValid(int x, int y, Node[][] grid) {
        return x >= 0 && x < grid.length && y >= 0 && y < grid[0].length && grid[x][y]!= null;
    }
}

public class Main {
    public static void main(String[] args) {
        Node[][] grid = new Node[5][5];
        for (int i = 0; i < grid.length; i++) {
            for (int j = 0; j < grid[i].length; j++) {
                grid[i][j] = new Node(i, j);
            }
        }

        Node startNode = grid[0][0];
        Node goalNode = grid[4][4];

        List<Node> path = AStar.findPath(startNode, goalNode, grid);
        if (path!= null) {
            System.out.println("Path found:");
            for (Node node : path) {
                System.out.println("Node: " + node.x + ", " + node.y);
            }
        } else {
            System.out.println("No path found");
        }
    }
}
