use std::env;
use std::error::Error;
use std::fmt;
use openssl::x509::X509;
use openssl::x509::extension::{SubjectAlternativeName, AsRef};

fn main() -> Result<(), Box<dyn Error>> {
    let domain = env::args().nth(1).expect("Usage: tls-scraper <domain>");
    let cert = get_certificate(&domain)?;
    let alt_names = extract_alt_names(&cert)?;

    println!("Alternate names for {}:\n", domain);
    for name in alt_names {
        println!("- {}", name);
    }

    Ok(())
}

fn get_certificate(domain: &str) -> Result<X509, Box<dyn Error>> {
    let conn = std::net::TcpStream::connect(format!("{}:443", domain))?
       .connect_timeout(std::time::Duration::from_secs(5))?.
        set_read_timeout(std::time::Duration::from_secs(5))?;

    let mut ssl_conn = openssl::ssl::SslConnector::builder(openssl::ssl::SslMethod::tls())?
       .connect(domain, conn)?;

    let cert = ssl_conn.peer_certificate()?.unwrap();
    Ok(cert)
}

fn extract_alt_names(cert: &X509) -> Result<Vec<String>, Box<dyn Error>> {
    let san = cert.extensions().iter().find(|ext| ext.critical() && ext.oid() == SubjectAlternativeName::oid()).unwrap();
    let san = san.value().as_ref().unwrap();

    let mut alt_names = Vec::new();
    for name in san.dns_names() {
        alt_names.push(name.to_string());
    }

    Ok(alt_names)
}
