            return jsonify({'error': 'Not found'}), 404

        item = items[item_id]
        response = make_response(jsonify(item))
        response.set_etag(md5(json.dumps(item).encode()).hexdigest())
        return response

    if request.method == 'PUT':
        if item_id not in items:
            return jsonify({'error': 'Not found'}), 404

        item = items[item_id]
        etag = md5(json.dumps(item).encode()).hexdigest()

        if not request.headers.get('If-Match') == etag:
            return jsonify({'error': 'Precondition Failed'}), 412

        item.update(request.json)
        items[item_id] = item

        response = make_response(jsonify(item))
        response.set_etag(md5(json.dumps(item).encode()).hexdigest())
        return response

if __name__ == '__main__':
