#include <iostream>
#include <string>
#include <vector>
#include <thread>
#include <mutex>
#include <curl/curl.h>

std::mutex mtx;

size_t writeCallback(char* buf, size_t size, size_t nmemb, void* up) {
    std::string* response = static_cast<std::string*>(up);
    response->append(buf, size * nmemb);
    return size * nmemb;
}

void makeRequest(const std::string& url) {
    CURL* curl = curl_easy_init();
    std::string response;
    if (curl) {
        curl_easy_setopt(curl, CURLOPT_URL, url.c_str());
        curl_easy_setopt(curl, CURLOPT_WRITEFUNCTION, writeCallback);
        curl_easy_setopt(curl, CURLOPT_WRITEDATA, &response);

        CURLcode res = curl_easy_perform(curl);
        if (res == CURLE_OK) {
            long status_code;
            curl_easy_getinfo(curl, CURLINFO_RESPONSE_CODE, &status_code);
            std::lock_guard<std::mutex> lock(mtx);
            std::cout << "URL: " << url << std::endl;
            std::cout << "Status code: " << status_code << std::endl;
            std::cout << "Response: " << response << std::endl;
        }
        curl_easy_cleanup(curl);
    }
}

int main() {
    std::vector<std::string> urls = {"http://example.com", "http://example.org", "http://example.net"};
    size_t concurrency_limit = 2;

    size_t num_requests = urls.size();
    size_t num_threads = std::min(num_requests, concurrency_limit);

    std::vector<std::thread> threads;
    for (size_t i = 0; i < num_threads; ++i) {
        threads.emplace_back(makeRequest, urls[i]);
    }

    for (size_t i = num_threads; i < num_requests; ++i) {
        threads[i % num_threads].join();
        threads[i % num_threads] = std::thread(makeRequest, urls[i]);
    }

    for (auto& thread : threads) {
        thread.join();
    }

    return 0;
}

