	s.users[user.ID] = user
	return nil
}

type MySQLStore struct {
	db *sql.DB
}

func NewMySQLStore(dataSourceName string) (*MySQLStore, error) {
	db, err := sql.Open("mysql", dataSourceName)
	if err!= nil {
		return nil, err
	}
	return &MySQLStore{db: db}, nil
}

func (s *MySQLStore) GetUser(id int) (*User, error) {
	var user User
	err := s.db.QueryRow("SELECT id, name FROM users WHERE id =?", id).Scan(&user.ID, &user.Name)
	if err!= nil {
		return nil, err
	}
	return &user, nil
}

func (s *MySQLStore) AddUser(user *User) error {
	_, err := s.db.Exec("INSERT INTO users (id, name) VALUES (?,?)", user.ID, user.Name)
	return err
}

