use std::time::{Duration, Instant};

struct TokenBucket {
    max_tokens: u32,
    tokens: u32,
    refill_rate: u32,
    last_refill: Instant,
}

impl TokenBucket {
    fn new(max_tokens: u32, refill_rate: u32) -> Self {
        TokenBucket {
            max_tokens,
            tokens: max_tokens,
            refill_rate,
            last_refill: Instant::now(),
        }
    }

    fn consume(&mut self, tokens: u32) -> bool {
        let now = Instant::now();
        let elapsed = now.duration_since(self.last_refill);
        let refill_tokens = (elapsed.as_secs() as u32) * self.refill_rate;
        self.tokens = self.tokens.saturating_add(refill_tokens);
        self.tokens = self.tokens.min(self.max_tokens);
        self.last_refill = now;

        if self.tokens >= tokens {
            self.tokens -= tokens;
            true
        } else {
            false
        }
    }
}

fn main() {
    let mut bucket = TokenBucket::new(100, 10);
    loop {
        std::thread::sleep(Duration::from_secs(1));
        if bucket.consume(10) {
            println!("10 tokens consumed");
        } else {
            println!("Not enough tokens");
        }
    }
}
