var store = sessions.NewCookieStore([]byte("secret-key"))

func generateSecureStateParameter() (string, error) {
	b := make([]byte, 32)
	_, err := rand.Read(b)
	if err!= nil {
		return "", err
	}
	return base64.URLEncoding.EncodeToString(b), nil
}

func oauthHandler(w http.ResponseWriter, r *http.Request) {
	state, err := generateSecureStateParameter()
	if err!= nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	session, _ := store.Get(r, "oauth-session")
	session.Values["state"] = state
	session.Save(r, w)

	authURL := fmt.Sprintf(
		"https://provider.example.com/oauth2/authorize?client_id=%s&redirect_uri=%s&response_type=code&state=%s",
		"your-client-id",
		"https://your-app.example.com/callback",
		state,
	)
	http.Redirect(w, r, authURL, http.StatusFound)
}

func oauthCallbackHandler(w http.ResponseWriter, r *http.Request) {
	session, _ := store.Get(r, "oauth-session")
	storedState := session.Values["state"].(string)
	receivedState := r.URL.Query().Get("state")

	if storedState!= receivedState {
		http.Error(w, "Invalid state parameter", http.StatusBadRequest)
		return
	}

	// Continue with OAuth2 flow...
	fmt.Fprintln(w, "State validation successful. Proceed with OAuth2 flow.")
}

