        model = CachedResponse
        fields = ['url', 'response', 'timestamp']
class ProxyAPIView(viewsets.ViewSet):
    def retrieve(self, request, pk=None):
        upstream_url = request.query_params.get('url')
        cached_response = cache.get(upstream_url)
        if cached_response is None:
            response = requests.get(upstream_url)
            cached_response, created = CachedResponse.objects.get_or_create(
                url=upstream_url,
                defaults={'response': response.text}
            )
            cache.set(upstream_url, cached_response.response, 60 * 60)  # Cache for 1 hour
        serializer = CachedResponseSerializer(cached_response)
        return Response(serializer.data)
