import time

class TooSoonError(Exception):
    pass

class ThrottledIterator:
    def __init__(self, func, interval, *args):
        self.func = func
        self.interval = interval
        self.args = args
        self.last_executed = 0

    def __iter__(self):
        return self

    def __next__(self):
        current_time = time.time()
        if current_time - self.last_executed < self.interval:
            raise TooSoonError(f'Function cannot be executed yet. Please wait {self.interval} seconds between executions.')
        self.last_executed = current_time
        return self.func(*self.args)
