import inspect
from typing import Any, Callable, get_type_hints

def validate_args(func: Callable) -> Callable:
    def wrapper(*args: Any, **kwargs: Any) -> Any:
        hints = get_type_hints(func)
        all_args = inspect.signature(func).bind(*args, **kwargs)
        all_args.apply_defaults()
        for name, value in all_args.arguments.items():
            expected_type = hints.get(name)
            if expected_type and not isinstance(value, expected_type):
                raise TypeError(f'Argument {name} is of type {type(value)}, ' \
                                f'but {expected_type} was expected.')
        return func(*args, **kwargs)
    return wrapper
