void tracePath(Node grid[ROW][COL], int destX, int destY) {
    printf("\nThe Path is ");
    int x = destX;
    int y = destY;
    while (!(grid[x][y].x == x && grid[x][y].y == y)) {
        int tempX = x;
        int tempY = y;
        x = grid[tempX][tempY].x;
        y = grid[tempX][tempY].y;
        printf("-> (%d,%d) ", x, y);
    }
    printf("\n");
}

void aStarSearch(int grid[ROW][COL], int srcX, int srcY, int destX, int destY) {
    Node nodeDetails[ROW][COL];
    int openList[ROW][COL] = {0};
    int closeList[ROW][COL] = {0};
    int foundDest = 0;

    memset(nodeDetails, 0, sizeof(nodeDetails));
    nodeDetails[srcX][srcY].f = 0;
    nodeDetails[srcX][srcY].g = 0;
    nodeDetails[srcX][srcY].h = 0;
    nodeDetails[srcX][srcY].x = srcX;
    nodeDetails[srcX][srcY].y = srcY;

    openList[srcX][srcY] = 1;

    while (foundDest == 0) {
        int x = -1, y = -1;
        int fMin = INT_MAX;

        for (int i = 0; i < ROW; i++) {
            for (int j = 0; j < COL; j++) {
                if (openList[i][j] == 1 && nodeDetails[i][j].f < fMin) {
                    fMin = nodeDetails[i][j].f;
                    x = i;
                    y = j;
                }
            }
        }

        openList[x][y] = 0;
        closeList[x][y] = 1;

        int fNew, gNew, hNew;

        if (isValid(x - 1, y) == 1) {
