type entry struct {
	key   string
	value interface{}
}

type hashMap struct {
	size  int
	table [][]entry
}

func newHashMap(size int) *hashMap {
	return &hashMap{
		size:  size,
		table: make([][]entry, size),
	}
}

func (h *hashMap) hash(key string) int {
	sum := 0
	for _, char := range key {
		sum += int(char)
	}
	return sum % h.size
}

func (h *hashMap) put(key string, value interface{}) {
	hash := h.hash(key)
	chain := h.table[hash]
	for i, e := range chain {
		if e.key == key {
			chain[i].value = value
			return
		}
	}
	chain = append(chain, entry{key, value})
	h.table[hash] = chain
}

func (h *hashMap) get(key string) (interface{}, bool) {
	hash := h.hash(key)
	chain := h.table[hash]
	for _, e := range chain {
		if e.key == key {
			return e.value, true
		}
	}
	return nil, false
}

func (h *hashMap) remove(key string) bool {
	hash := h.hash(key)
	chain := h.table[hash]
	for i, e := range chain {
		if e.key == key {
			copy(chain[i:], chain[i+1:])
			chain[len(chain)-1] = entry{}
			chain = chain[:len(chain)-1]
			h.table[hash] = chain
			return true
		}
	}
	return false
}

func main() {
	hm := newHashMap(10)
	hm.put("key1", "value1")
	hm.put("key2", "value2")
	fmt.Println(hm.get("key1"))
	fmt.Println(hm.get("key2"))
	hm.remove("key1")
	fmt.Println(hm.get("key1"))
}
