class ListNode {
  constructor(val = 0, next = null) {
    this.val = val;
    this.next = next;
  }
}

const mergeKLists = (lists) => {
  const heap = new MinHeap();
  lists.forEach((list) => {
    if (list) heap.insert(list);
  });
  const dummy = new ListNode();
  let current = dummy;
  while (heap.size()) {
    const node = heap.extractMin();
    current.next = node;
    current = current.next;
    if (node.next) heap.insert(node.next);
  }
  return dummy.next;
};

class MinHeap {
  constructor() {
    this.heap = [];
  }

  size() {
    return this.heap.length;
  }

  insert(node) {
    this.heap.push(node);
    this.bubbleUp(this.heap.length - 1);
  }

  extractMin() {
    const min = this.heap[0];
    const last = this.heap.pop();
    if (this.heap.length > 0) {
      this.heap[0] = last;
      this.bubbleDown(0);
    }
    return min;
  }

  bubbleUp(index) {
    while (index > 0) {
      const parentIndex = Math.floor((index - 1) / 2);
      if (this.heap[parentIndex].val <= this.heap[index].val) break;
      [this.heap[parentIndex], this.heap[index]] = [this.heap[index], this.heap[parentIndex]];
      index = parentIndex;
    }
  }

  bubbleDown(index) {
    while (true) {
      const leftChildIndex = 2 * index + 1;
      const rightChildIndex = 2 * index + 2;
      let minIndex = index;
      if (
        leftChildIndex < this.heap.length &&
        this.heap[leftChildIndex].val < this.heap[minIndex].val
      ) {
        minIndex = leftChildIndex;
      }
      if (
        rightChildIndex < this.heap.length &&
        this.heap[rightChildIndex].val < this.heap[minIndex].val
      ) {
        minIndex = rightChildIndex;
      }
      if (minIndex === index) break;
      [this.heap[index], this.heap[minIndex]] = [this.heap[minIndex], this.heap[index]];
      index = minIndex;
    }
  }
}
