func (kv *KVStore) Set(key string, value interface{}, expiration time.Duration) {
    kv.mu.Lock()
    defer kv.mu.Unlock()
    if expiration > 0 {
        kv.store[key] = entry{value, time.Now().Add(expiration)}
    } else {
        kv.store[key] = entry{value, time.Time{}}
    }
}

func (kv *KVStore) Get(key string) (interface{}, bool) {
    kv.mu.RLock()
    defer kv.mu.RUnlock()
    entry, ok := kv.store[key]
    if!ok || (entry.expiry!= time.Time{} && time.Now().After(entry.expiry)) {
        return nil, false
    }
    return entry.value, true
}

func (kv *KVStore) Delete(key string) {
    kv.mu.Lock()
    defer kv.mu.Unlock()
    delete(kv.store, key)
}
