function retryWithExponentialBackoff(task, maxAttempts, baseDelay, jitterFactor) {
  return new Promise((resolve, reject) => {
    let attempts = 0;

    function attempt() {
      attempts++;
      task()
       .then(resolve)
       .catch((error) => {
          if (attempts < maxAttempts) {
            const delay = baseDelay * Math.pow(2, attempts);
            const jitter = Math.random() * jitterFactor * delay;
            const totalDelay = delay + jitter;
            setTimeout(attempt, totalDelay);
          } else {
            reject(error);
          }
        });
    }

    attempt();
  });
}
