use hmac::{Hmac, Mac, NewMac};
use sha2::Sha256;
use base32;
use serde::{Deserialize, Serialize};

const SECRET_KEY: &'static str = "your_secret_key_here";

#[derive(Serialize, Deserialize)]
struct User {
    id: u32,
    email: String,
    totp_secret: String,
}

impl User {
    fn generate_totp(&self) -> String {
        let secret_bytes = base32::decode(self.totp_secret.as_bytes()).unwrap();
        let timestamp = SystemTime::now().duration_since(UNIX_EPOCH).unwrap().as_secs() / 30;
        let mut mac = Hmac::<Sha256>::new_varkey(&secret_bytes).unwrap();
        mac.update(&timestamp.to_be_bytes());
        let code = mac.finalize().into_bytes();
        let offset = (code[code.len() - 1] & 0xf) as usize;
        let binary = ((code[offset] & 0x7f) << 24) | ((code[offset + 1] & 0xff) << 16) | ((code[offset + 2] & 0xff) << 8) | (code[offset + 3] & 0xff);
        let token = binary % 1_000_000;
        format!("{:06}", token)
    }

    fn verify_totp(&self, input_code: &str) -> bool {
        let current_code = self.generate_totp();
        constant_time_eq::constant_time_eq(current_code.as_bytes(), input_code.as_bytes())
    }
}

