function breadthFirstSearch(maze, start, end) {
  const queue = [start];
  const visited = new Set([start.toString()]);
  const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];
  const previous = new Map();

  while (queue.length > 0) {
    const current = queue.shift();

    if (current[0] === end[0] && current[1] === end[1]) {
      return buildPath(previous, start, end);
    }

    for (const [dx, dy] of directions) {
      const next = [current[0] + dx, current[1] + dy];
      const key = next.toString();

      if (isValid(maze, next) &&!visited.has(key)) {
        queue.push(next);
        visited.add(key);
        previous.set(key, current);
      }
    }
  }

  return null;
}

function isValid(maze, position) {
  const [row, col] = position;
  return (
    row >= 0 && row < maze.length &&
    col >= 0 && col < maze[0].length &&
    maze[row][col] === 0
  );
}

function buildPath(previous, start, end) {
  const path = [];
  let current = end;

  while (current[0]!== start[0] || current[1]!== start[1]) {
    path.unshift(current);
    current = previous.get(current.toString());
  }

  path.unshift(start);
  return path;
}
