use std::cell::RefCell;
use std::rc::Rc;

type TreeNodeRef = Rc<RefCell<TreeNode>>;

// Definition for a binary tree node.
struct TreeNode {
    val: i32,
    left: Option<TreeNodeRef>,
    right: Option<TreeNodeRef>,
}

impl TreeNode {
    fn new(val: i32) -> Self {
        TreeNode {
            val,
            left: None,
            right: None,
        }
    }
}

fn serialize(root: Option<TreeNodeRef>) -> Vec<Option<i32>> {
    let mut result = Vec::new();
    let mut queue = std::collections::VecDeque::new();
    queue.push_back(root.clone());

    while!queue.is_empty() {
        let node_option = queue.pop_front().unwrap();
        match node_option {
            Some(node_ref) => {
                let node = node_ref.borrow();
                result.push(Some(node.val));
                queue.push_back(node.left.clone());
                queue.push_back(node.right.clone());
            }
            None => {
                result.push(None);
            }
        }
    }
    result
}

fn deserialize(data: Vec<Option<i32>>) -> Option<TreeNodeRef> {
    if data.is_empty() || data[0].is_none() {
        return None;
    }

    let root = Rc::new(RefCell::new(TreeNode::new(data[0].unwrap())));
    let mut queue = std::collections::VecDeque::new();
    queue.push_back(root.clone());

    let mut i = 1;
    while!queue.is_empty() {
        let node = queue.pop_front().unwrap();
        if i < data.len() {
            if let Some(val) = data[i] {
                let left = Rc::new(RefCell::new(TreeNode::new(val)));
                node.borrow_mut().left = Some(left.clone());
                queue.push_back(left);
            }
            i += 1;
        }
        if i < data.len() {
            if let Some(val) = data[i] {
                let right = Rc::new(RefCell::new(TreeNode::new(val)));
                node.borrow_mut().right = Some(right.clone());
                queue.push_back(right);
            }
            i += 1;
        }
    }
    Some(root)
}
