template<typename Key, typename Value>
class LRUCache {
public:
    LRUCache(size_t maxSize) : _maxSize(maxSize) {}

    void put(const Key& key, const Value& value) {
        if (_cache.find(key)!= _cache.end()) {
            _lru.splice(_lru.begin(), _lru, _cache[key]);
            _cache[key]->second = value;
        } else {
            if (_cache.size() >= _maxSize) {
                Key evictedKey = _lru.back().first;
                _lru.pop_back();
                _cache.erase(evictedKey);
            }
            _lru.emplace_front(key, value);
            _cache[key] = _lru.begin();
        }
    }

    Value get(const Key& key) {
        if (_cache.find(key) == _cache.end()) {
            throw std::out_of_range("Key not found in cache");
        }
        _lru.splice(_lru.begin(), _lru, _cache[key]);
        return _cache[key]->second;
    }

private:
    size_t _maxSize;
    std::list<std::pair<Key, Value>> _lru;
    std::unordered_map<Key, typename std::list<std::pair<Key, Value>>::iterator> _cache;
};

int main() {
    LRUCache<int, std::string> cache(3);
    cache.put(1, "one");
    cache.put(2, "two");
    cache.put(3, "three");

