func fileHandler(w http.ResponseWriter, r *http.Request) {
    userPath := r.URL.Query().Get("path")
    basePath := "/var/www/files/"

    // Clean the user-provided path to prevent path traversal
    cleanedPath := filepath.Clean(userPath)

    // Join the base path and cleaned path
    filePath := filepath.Join(basePath, cleanedPath)

    // Check if the requested file exists and is within the base path
    fileInfo, err := os.Stat(filePath)
    if os.IsNotExist(err) ||!strings.HasPrefix(filePath, basePath) {
        http.NotFound(w, r)
        return
    }

    // Serve the file
    http.ServeFile(w, r, filePath)
}
