package main

import (
    "fmt"
    "math/rand"
    "time"
)

func init() {
    rand.Seed(time.Now().UnixNano())
}

func quicksort(arr []int) []int {
    if len(arr) <= 1 {
        return arr
    }

    pivotIndex := rand.Intn(len(arr))
    arr = swap(arr, pivotIndex, len(arr)-1)
    pivot := arr[len(arr)-1]

    left, right := partition(arr, pivot)

    left = quicksort(left)
    right = quicksort(right)

    return append(append([]int{}, left...), right...)
}

func partition(arr []int, pivot int) ([]int, []int) {
    less := make([]int, 0)
    greater := make([]int, 0)

    for _, num := range arr[:len(arr)-1] {
        if num < pivot {
            less = append(less, num)
        } else {
            greater = append(greater, num)
        }
    }

    return less, greater
}

func swap(arr []int, i, j int) []int {
    arr[i], arr[j] = arr[j], arr[i]
    return arr
}

func main() {
    arr := []int{5, 3, 6, 2, 10, 8, 1, 7, 4, 9}
    fmt.Println("Original array:", arr)
    sortedArr := quicksort(arr)
    fmt.Println("Sorted array:", sortedArr)
}
