    return memory_usage * getpagesize() / 1024;
}

int main(int argc, char* argv[]) {
    if (argc!= 2) {
        printf("Usage: %s <pid>\n", argv[0]);
        return 1;
    }
    pid_t pid = atoi(argv[1]);
    FILE* log_file = fopen("memory_usage.log", "w");
    if (log_file == NULL) {
        perror("Failed to open log file");
        return 1;
    }
    long total_memory = 0;
    long peak_memory = 0;
    int count = 0;
    while (1) {
        long memory_usage = get_memory_usage(pid);
        if (memory_usage == -1) {
            break;
        }
        total_memory += memory_usage;
        if (memory_usage > peak_memory) {
            peak_memory = memory_usage;
        }
        fprintf(log_file, "Timestamp: %ld, Memory Usage: %ld KB\n", time(NULL), memory_usage);
        fflush(log_file);
        count++;
        sleep(1);
    }
    fclose(log_file);
    printf("Total Memory Used: %ld KB\n", total_memory);
    printf("Average Memory Usage: %ld KB\n", total_memory / count);
    printf("Peak Memory Usage: %ld KB\n", peak_memory);
    return 0;
}
