package main

import (
    "fmt"
    "sync"
    "time"
)

func debounce(callback func(), duration time.Duration) func() {
    var mutex sync.Mutex
    timer := time.NewTimer(0)
    return func() {
        mutex.Lock()
        defer mutex.Unlock()
        if!timer.Stop() {
            return
        }
        timer.Reset(duration)
        go func() {
            <-timer.C
            callback()
        }()
    }
}

func throttle(callback func(), interval time.Duration) func() {
    var mutex sync.Mutex
    lastExecution := time.Now()
    return func() {
        mutex.Lock()
        defer mutex.Unlock()
        if time.Since(lastExecution) >= interval {
            callback()
            lastExecution = time.Now()
        }
    }
}

func main() {
    debounced := debounce(func() {
        fmt.Println("Debounced callback executed!")
    }, 500*time.Millisecond)

    throttled := throttle(func() {
        fmt.Println("Throttled callback executed!")
    }, 1*time.Second)

    for i := 0; i < 10; i++ {
        debounced()
        throttled()
        time.Sleep(200 * time.Millisecond)
    }
}
