class Parser:
    def __init__(self, tokens):
        self.tokens = tokens
        self.current_token = None
        self.index = -1
        self.advance()

    def advance(self):
        self.index += 1
        if self.index < len(self.tokens):
            self.current_token = self.tokens[self.index]
        else:
            self.current_token = None

    def parse(self):
        result = self.expression()
        if self.current_token is not None:
            raise SyntaxError('Invalid syntax')
        return result

    def expression(self):
        result = self.term()
        while self.current_token in ('+', '-')):
            if self.current_token == '+':
                self.advance()
                result += self.term()
            elif self.current_token == '-':
                self.advance()
                result -= self.term()
        return result

    def term(self):
        result = self.factor()
        while self.current_token in ('*', '/')):
            if self.current_token == '*':
                self.advance()
                result *= self.factor()
            elif self.current_token == '/':
                self.advance()
                result /= self.factor()
        return result

    def factor(self):
        if self.current_token == '(':
            self.advance()
            result = self.expression()
            if self.current_token!= ')':
                raise SyntaxError('Missing closing parenthesis')
            self.advance()
            return result
        elif self.current_token.replace('.', '', 1).isdigit():
            result = float(self.current_token)
            self.advance()
            return result
        else:
            raise SyntaxError('Invalid token')
