#include <boost/asio.hpp>
#include <boost/filesystem.hpp>
#include <iostream>
#include <fstream>
#include <sstream>

using boost::asio::ip::tcp;

std::string generate_directory_listing(const std::string& path) {
    std::stringstream ss;
    ss << "<html><body>";
    for (const auto& entry : boost::filesystem::directory_iterator(path)) {
        const std::string entry_name = entry.path().filename().string();
        if (entry.is_regular_file()) {
            ss << "<a href='" << entry_name << "'>" << entry_name << "</a><br>";
        } else if (entry.is_directory()) {
            ss << "<a href='" << entry_name << "/'>" << entry_name << "/</a><br>";
        }
    }
    ss << "</body></html>";
    return ss.str();
}

void handle_request(tcp::socket socket) {
    boost::system::error_code ec;
    boost::asio::streambuf request_buf;
    boost::asio::read_until(socket, request_buf, "\r\n\r\n", ec);
    if (ec) return;

    std::istream request_stream(&request_buf);
    std::string method, uri, version;
    request_stream >> method >> uri >> version;
    std::string path = uri.substr(1);
    if (path.empty()) path = ".";

    std::string content;
    boost::filesystem::path fs_path(path);
    if (boost::filesystem::exists(fs_path)) {
        if (boost::filesystem::is_regular_file(fs_path)) {
            std::ifstream file(fs_path.string(), std::ios::in | std::ios::binary);
            content.assign((std::istreambuf_iterator<char>(file)), std::istreambuf_iterator<char>());
        } else if (boost::filesystem::is_directory(fs_path)) {
            content = generate_directory_listing(fs_path.string());
        }
    }

    std::ostringstream response;
    response << "HTTP/1.1 200 OK\r\n";
    response << "Content-Type: text/html\r\n";
    response << "Content-Length: " << content.size() << "\r\n\r\n";
    response << content;

    boost::asio::write(socket, boost::asio::buffer(response.str()), ec);
}

int main(int argc, char* argv[]) {
    try {
        boost::asio::io_context io_context;
        tcp::acceptor acceptor(io_context, tcp::endpoint(tcp::v4(), 8080));
        for (;;) {
            tcp::socket socket(io_context);
            acceptor.accept(socket);
            std::thread(handle_request, std::move(socket)).detach();
        }
    } catch (std::exception& e) {
        std::cerr << "Exception: " << e.what() << "\n";
    }

    return 0;
}

