class MinHeap {
    private $heap;

    public function __construct() {
        $this->heap = array();
    }

    public function insert($value) {
        $this->heap[] = $value;
        $this->bubbleUp(count($this->heap) - 1);
    }

    public function extractMin() {
        if (empty($this->heap)) {
            throw new Exception("Heap is empty");
        }

        $min = $this->heap[0];
        $last = array_pop($this->heap);

        if (!empty($this->heap)) {
            $this->heap[0] = $last;
            $this->bubbleDown(0);
        }

        return $min;
    }

    public function getMin() {
        if (empty($this->heap)) {
            throw new Exception("Heap is empty");
        }

        return $this->heap[0];
    }

    private function bubbleUp($index) {
        $parent = ($index - 1) / 2;

        while ($index > 0 && $this->heap[$parent] > $this->heap[$index]) {
            $tmp = $this->heap[$parent];
            $this->heap[$parent] = $this->heap[$index];
            $this->heap[$index] = $tmp;

            $index = $parent;
            $parent = ($index - 1) / 2;
        }
    }

    private function bubbleDown($index) {
        $left = 2 * $index + 1;
        $right = 2 * $index + 2;
        $smallest = $index;

        if ($left < count($this->heap) && $this->heap[$left] < $this->heap[$smallest]) {
            $smallest = $left;
        }

        if ($right < count($this->heap) && $this->heap[$right] < $this->heap[$smallest]) {
            $smallest = $right;
        }

        if ($smallest!= $index) {
            $tmp = $this->heap[$smallest];
            $this->heap[$smallest] = $this->heap[$index];
            $this->heap[$index] = $tmp;

            $this->bubbleDown($smallest);
        }
    }
}
