#include <iostream>
#include <vector>

template <typename T>
class CircularBuffer {
private:
    std::vector<T> buffer;
    size_t head;
    size_t tail;
    size_t size;
    bool isFull;

public:
    CircularBuffer(size_t capacity) : buffer(capacity), head(0), tail(0), size(0), isFull(false) {}

    void add(T element) {
        if (isFull) {
            tail = (tail + 1) % buffer.size();
        } else {
            size++;
            isFull = (size == buffer.size());
        }
        buffer[head] = element;
        head = (head + 1) % buffer.size();
    }

    T remove() {
        if (isEmpty()) {
            throw std::runtime_error("Buffer is empty");
        }
        T element = buffer[tail];
        tail = (tail + 1) % buffer.size();
        size--;
        isFull = false;
        return element;
    }

    bool isEmpty() const {
        return size == 0;
    }

    bool isFull() const {
        return isFull;
    }
};
