package main

import (
    "crypto/rand"
    "encoding/base64"
    "fmt"
    "net/http"
)

func generateToken() (string, error) {
    b := make([]byte, 32)
    _, err := rand.Read(b)
    if err!= nil!= nil {
        return "", err
    }
    return base64.URLEncoding.EncodeToString(b), nil
}

func handleFormPage(w http.ResponseWriter, r *http.Request) {
    token, err := generateToken()
    if err!= nil {
        http.Error(w, err.Error(), http.StatusInternalServerError)
        return
    }
    sessionToken := fmt.Sprintf("%s=%s", "X-CSRF-Token", token)
    http.SetCookie(w, &http.Cookie{
        Name:  "X-CSRF-Token",
        Value: token,
    })
    fmt.Fprintf(w, "<form method=\"POST\" action=\"/submit\">")
    fmt.Fprintf(w, "<input type=\"hidden\" name=\"X-CSRF-Token\" value=\"%s\">", token)
    fmt.Fprintf(w, "<input type=\"submit\" value=\"Submit\">")
    fmt.Fprintf(w, "</form>")
}

func handleSubmit(w http.ResponseWriter, r *http.Request) {
    sessionToken, err := r.Cookie("X-CSRF-Token")
    if err!= nil {
        http.Error(w, "No session token", http.StatusUnauthorized)
        return
    }
    formToken := r.FormValue("X-CSRF-Token")
    if formToken!= sessionToken.Value {
        http.Error(w, "Invalid CSRF token", http.StatusUnauthorized)
        return
    }
    fmt.Fprintf(w, "Form submitted successfully!")
}

func main() {
    http.HandleFunc("/", handleFormPage)
    http.HandleFunc("/submit", handleSubmit)
    http.ListenAndServe(":8080", nil)
