fn quicksort<T: Ord>(arr: &mut [T]) {
    if arr.len() <= 1 {
        return;
    }
    let pivot_index = rand::random::<usize>() % arr.len();
    arr.swap(pivot_index, arr.len() - 1);
    let pivot = &arr[arr.len() - 1];
    let mut i = 0;
    for j in 0..arr.len() - 1 {
        if &arr[j] < pivot {
            arr.swap(i, j);
            i += 1;
        }
    }
    arr.swap(i, arr.len() - 1);
    quicksort(&mut arr[..i]);
    quicksort(&mut arr[i + 1..]);
}
