use std::sync::{Arc, Mutex};
use std::time::Duration;
use std::collections::HashMap;

struct RateLimiter<T> where T: Eq + std::hash::Hash {
    counts: Arc<Mutex<HashMap<T, (u64, std::time::Instant)>>>,
    max_requests: u64,
    window_size: Duration,
}

impl<T> RateLimiter<T> where T: Eq + std::hash::Hash + Copy {
    fn new(max_requests: u64, window_size: Duration) -> Self {
        RateLimiter {
            counts: Arc::new(Mutex::new(HashMap::new())),
            max_requests,
            window_size,
        }
    }

    fn check(&self, key: T) -> bool {
        let mut counts = self.counts.lock().unwrap();
        let now = std::time::Instant::now();

        counts.entry(key).and_modify(|(count, last_request)| {
            let elapsed = now.duration_since(*last_request);
            if elapsed >= self.window_size {
                *count = 1;
            } else {
                *count += 1;
            }
            *last_request = now;
        }).or_insert((1, now));

        let (count, _) = counts.get(&key).unwrap();
        *count <= self.max_requests
    }
}
