package main

import (
    "fmt"
    "net"
    "os"
    "strings"
    "time"
)

func main() {
    if len(os.Args)!= 2 {
        fmt.Println("Usage: ping_sweep <subnet>")
        os.Exit(1)
    }

    subnet := os.Args[1]
    liveHosts := make([]string, 0)

    ip, ipnet, err := net.ParseCIDR(subnet)
    if err!= nil {
        fmt.Printf("Invalid subnet: %s\n", subnet)
        os.Exit(1)
    }

    for ip := ip.Mask(ipnet.Mask); ipnet.Contains(ip); inc(ip) {
        result, err := ping(ip.String())
        if err!= nil {
            continue
        }

        if result {
            liveHosts = append(liveHosts, ip.String())
        }
    }

    fmt.Println("Live hosts:")
    for _, host := range liveHosts {
        fmt.Println(host)
    }
}

func ping(ip string) (bool, error) {
    timeout := time.Second * 1
    cmd := fmt.Sprintf("ping -c 1 -W %d %s", int(timeout.Seconds()), ip)
    output, err := exec.Command("sh", "-c", cmd).CombinedOutput()
    if err!= nil {
        if strings.Contains(string(output), "100% packet loss") {
            return false, nil
        }
        return false, err
    }

    return true, nil
}

func inc(ip net.IP) {
    for j := len(ip) - 1; j >= 0; j-- {
        ip[j]++
        if ip[j] > 0 {
            break
        }
    }
}
