from __future__ import annotations
from abc import ABC, abstractmethod


class Command(ABC):
    @abstractmethod
    def execute(self) -> None:
        pass

    @abstractmethod
    def undo(self) -> None:
        pass


class Calculator:
    def __init__(self):
        self.current = 0
        self.history: list[Command] = []

    def execute_command(self, command: Command):
        self.current = command.execute()
        self.history.append(command)

    def undo_last_command(self):
        if self.history:
            command = self.history.pop()
            self.current = command.undo()


class AddCommand(Command):
    def __init__(self, calculator: Calculator, value: float):
        self.calculator = calculator
        self.value = value

    def execute(self) -> float:
        return self.calculator.current + self.value

    def undo(self) -> float:
        return self.calculator.current - self.value


class SubtractCommand(Command):
    def __init__(self, calculator: Calculator, value: float):
        self.calculator = calculator
        self.value = value

    def execute(self) -> float:
        return self.calculator.current - self.value

    def undo(self) -> float:
        return self.calculator.current + self.value


class MultiplyCommand(Command):
    def __init__(self, calculator: Calculator, value: float):
        self.calculator = calculator
        self.value = value
        self.prev_value = calculator.current

    def execute(self) -> float:
        return self.calculator.current * self.value

    def undo(self) -> float:
        return self.prev_value


class DivideCommand(Command):
    def __init__(self, calculator: Calculator, value: float):
        self.calculator = calculator
        self.value = value
        self.prev_value = calculator.current

    def execute(self) -> float:
        return self.calculator.current / self.value

    def undo(self) -> float:
        return self.prev_value


def main():
    calculator = Calculator()

    calculator.execute_command(AddCommand(calculator, 10))
    print(f"Current value: {calculator.current}")  # Output: 10

    calculator.execute_command(MultiplyCommand(calculator, 5))
    print(f"Current value: {calculator.current}")  # Output: 50

    calculator.execute_command(SubtractCommand(calculator, 7))
    print(f"Current value: {calculator.current}")  # Output: 43

    calculator.execute_command(DivideCommand(calculator, 2))
    print(f"Current value: {calculator.current}")  # Output: 21.5

    calculator.undo_last_command()
    print(f"Current value: {calculator.current}")  # Output: 43

    calculator.undo_last_command()
    print(f"Current value: {calculator.current}")  # Output: 50

if __name__ == "__main__":
    main()
