    timeval tv{};
    tv.tv_sec = timeout;
    setsockopt(sock, SOL_SOCKET, SO_RCVTIMEO, (const char*)&tv, sizeof(tv));

    if (connect(sock, (sockaddr*)&address, sizeof(address)) == 0) {
        char buffer[1024];
        ssize_t bytesRead = recv(sock, buffer, sizeof(buffer) - 1, 0);
        close(sock);
        if (bytesRead > 0) {
            buffer[bytesRead] = '\0';
            return buffer;
        }
    }
    close(sock);
    return "";
}

int main(int argc, char* argv[]) {
    if (argc!= 5) {
        std::cerr << "Usage: " << argv[0] << " <IP> <start_port> <end_port> <timeout>" << std::endl;
        return 1;
    }

    std::string ipAddress = argv[1];
    int startPort = std::stoi(argv[2]);
    int endPort = std::stoi(argv[3]);
    int timeout = std::stoi(argv[4]);

    for (int port = startPort; port <= endPort; ++port) {
        std::string banner = getBanner(ipAddress, port, timeout);
        if (!banner.empty()) {
            std::cout << "Port " << port << ": " << banner << std::endl;
        }
    }

    return 0;
}

