        wall_normal = get_wall_normal()
        velocity = wall_normal.cross(direction).normalized() * wall_run_speed

    if Input.is_action_just_pressed("jump"):
        if is_on_floor():
            velocity.y = jump_force
        elif wall_running:
            velocity = wall_normal * wall_jump_force + direction * wall_run_speed
            wall_running = false

    move_and_slide()

func get_wall_normal() -> Vector3:
