package com.example.scene_transitions;

import net.fabricmc.api.ModInitializer;
import net.fabricmc.fabric.api.event.lifecycle.v1.ServerTickEvents;
import net.minecraft.server.MinecraftServer;
import net.minecraft.util.math.Vec3d;
import net.minecraft.world.dimension.DimensionType;

public class SceneTransitionMod implements ModInitializer {
    private static final int FADE_DURATION = 40; // Duration of the fade in ticks
    private static final int TRANSITION_DURATION = 100; // Duration of the transition in ticks
    private int fadeTimer = 0;
    private int transitionTimer = 0;
    private boolean isTransitioning = false;

    @Override
    public void onInitialize() {
        ServerTickEvents.END_SERVER_TICK.register(this::onServerTick);
    }

    private void onServerTick(MinecraftServer server) {
        if (isTransitioning) {
            if (fadeTimer < FADE_DURATION) {
                fadeTimer++;
                // Fade out the current scene
                float fadeAmount = (float) fadeTimer / FADE_DURATION;
                server.execute(() -> {
                    for (ServerPlayerEntity player : server.getPlayerManager().getPlayerList()) {
                        player.setCameraPos(new Vec3d(0, -1000, 0)); // Move the camera away to create a fade effect
                    }
                });
            } else if (transitionTimer < TRANSITION_DURATION) {
                transitionTimer++;
                // Load the new scene in the background
                if (transitionTimer == 1) {
                    server.execute(() -> {
                        // Teleport players to the new dimension or location
                        for (ServerPlayerEntity player : server.getPlayerManager().getPlayerList()) {
                            player.teleport(DimensionType.THE_NETHER, new Vec3d(0, 100, 0), 0, 0); // Example: Teleport to the Nether dimension
                        }
                    });
                }
            } else {
                // Fade in the new scene
                float fadeAmount = 1.0f - (float) (transitionTimer - TRANSITION_DURATION) / FADE_DURATION;
                server.execute(() -> {
                    for (ServerPlayerEntity player : server.getPlayerManager().getPlayerList()) {
                        player.setCameraPos(player.getPos()); // Restore the camera position
                    }
                });
                if (transitionTimer >= TRANSITION_DURATION + FADE_DURATION) {
                    isTransitioning = false;
                }
                transitionTimer++;
            }
        }
    }

    public void startTransition() {
        isTransitioning = true;
        fadeTimer = 0;
        transitionTimer = 0;
    }
}
