import time
from functools import wraps


class Debounce:
    def __init__(self, milliseconds):
        self.milliseconds = milliseconds
        self.last_call = 0

    def __call__(self, func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            now = int(time.time() * 1000)
            if now - self.last_call >= self.milliseconds:
                self.last_call = now
                return func(*args, **kwargs)
        return wrapper


class Throttle:
    def __init__(self, milliseconds):
        self.milliseconds = milliseconds
        self.last_call = 0

    def __call__(self, func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            now = int(time.time() * 1000)
            if now - self.last_call >= self.milliseconds:
                self.last_call = now
                return func(*args, **kwargs)
        return wrapper


@Debounce(milliseconds=500)
def debounced_callback():
    print("Debounced callback called")

@Throttle(milliseconds=1000)
def throttled_callback():
    print("Throttled callback called")

# Example usage:
# debounced_callback()  # Called immediately
# debounced_callback()  # Not called if less than 500ms since last call
# throttled_callback()  # Called immediately
# throttled_callback()  # Not called if less than 1000ms since last call
