use std::collections::HashMap;
use std::rc::Rc;
use std::cell::RefCell;

struct LRUCache {
    capacity: usize,
    map: HashMap<i32, Rc<RefCell<ListNode>>>,
    head: Option<Rc<RefCell<ListNode>>>,
    tail: Option<Rc<RefCell<ListNode>>>,
}

struct ListNode {
    key: i32,
    value: i32,
    prev: Option<Rc<RefCell<ListNode>>>,
    next: Option<Rc<RefCell<ListNode>>>,
}

impl LRUCache {
    fn new(capacity: usize) -> Self {
        LRUCache {
            capacity,
            map: HashMap::new(),
            head: None,
            tail: None,
        }
    }

    fn get(&mut self, key: i32) -> i32 {
        if let Some(node) = self.map.get(&key) {
            let value = node.borrow().value;
            self.move_to_front(node.clone());
            value
        } else {
            -1
        }
    }

    fn put(&mut self, key: i32, value: i32) {
        if let Some(node) = self.map.get(&key) {
            node.borrow_mut().value = value;
            self.move_to_front(node.clone());
        } else {
            let new_node = Rc::new(RefCell::new(ListNode::new(key, value)));
            if self.map.len() >= self.capacity {
                let tail_key = self.tail.as_ref().unwrap().borrow().key;
                self.map.remove(&tail_key);
                self.remove_from_list(self.tail.take().unwrap());
            }
            self.map.insert(key, new_node.clone());
            self.insert_at_front(new_node);
        }
    }

    fn move_to_front(&mut self, node: Rc<RefCell<ListNode>>) {
        if node.borrow().prev.is_none() {
            // Already at the front
            return;
        }
        self.remove_from_list(node.clone());
        self.insert_at_front(node);
    }

    fn remove_from_list(&mut self, node: Rc<RefCell<ListNode>>) {
        let prev = node.borrow_mut().prev.take();
        let next = node.borrow_mut().next.take();
        match (prev, next) {
            (Some(prev), Some(next)) => {
                prev.borrow_mut().next = Some(next.clone());
                next.borrow_mut().prev = Some(prev);
            }
            (Some(prev), None) => {
                prev.borrow_mut().next = None;
                self.tail = Some(prev);
            }
            (None, Some(next)) => {
                next.borrow_mut().prev = None;
                self.head = Some(next);
            }
            (None, None) => {
                self.head = None;
                self.tail = None;
            }
        }
    }

    fn insert_at_front(&mut self, node: Rc<RefCell<ListNode>>) {
        if let Some(head) = self.head.take() {
            node.borrow_mut().next = Some(head.clone());
            head.borrow_mut().prev = Some(node.clone());
        }
        self.head = Some(node.clone());
        if self.tail.is_none() {
            self.tail = Some(node.clone());
        }
    }
}

impl ListNode {
    fn new(key: i32, value: i32) -> Self {
        ListNode {
            key,
            value,
            prev: None,
            next: None,
        }
    }
}
