func hashPassword(password string) (string, error) {
salt := make([]byte, 16)
_, err := rand.Read(salt)
if err!= nil {
return "", err
}

hash := argon2.IDKey([]byte(password), salt, 1, 64*1024, 4, 32)
b64Salt := base64.RawStdEncoding.EncodeToString(salt)
b64Hash := base64.RawStdEncoding.EncodeToString(hash)

return "$argon2id$v=19$m=65536,t=1,p=4$" + b64Salt + "$" + b64Hash, nil
}

func verifyPassword(hash, password string) (bool, error) {
p, err := argon2id.Parse(hash)
if err!= nil {
return false, err
}

otherHash := argon2.IDKey([]byte(password), p.Salt, p.Iterations, p.Memory, p.Parallelism, p.KeyLength)

return subtle.ConstantTimeCompare(p.Key, otherHash) == 1, nil
}

func main() {
password := "testpassword"
hashed, err := hashPassword(password)
if err!= nil {
panic(err)
}
fmt.Println("Hash: ", hashed)

match, err := verifyPassword(hashed, password)
if err!= nil {
panic(err)
}

fmt.Println("Match: ", match)
}
