from django.db import models
from rest_framework import serializers, viewsets
from rest_framework.response import Response
from rest_framework.status import HTTP_412_PRECONDITION_FAILED


class OptimisticModel(models.Model):
    name = models.CharField(max_length=100)
    value = models.IntegerField()
    version = models.IntegerField(default=0)

    def __str__(self):
        return self.name

    def increment_version(self):
        self.version += 1
        self.save()


class OptimisticModelSerializer(serializers.ModelSerializer):
    class Meta:
        model = OptimisticModel
        fields = ['id', 'name', 'value', 'version']

    def update(self, instance, validated_data):
        request = self.context.get('request')
        if request and 'HTTP_IF_MATCH' in request.META:
            etag = request.META['HTTP_IF_MATCH']
            if etag!= instance.get_etag():
                raise serializers.ValidationError('ETag mismatch', code=HTTP_412_PRECONDITION_FAILED)
        return super().update(instance, validated_data)


class OptimisticModelViewSet(viewsets.ModelViewSet):
    queryset = OptimisticModel.objects.all()
    serializer_class = OptimisticModelSerializer

    def retrieve(self, request, *args, **kwargs):
        instance = self.get_object()
        serializer = self.get_serializer(instance)
        response = Response(serializer.data)
        response['ETag'] = instance.get_etag()
        return response

    def update(self, request, *args, **kwargs):
        instance = self.get_object()
        serializer = self.get_serializer(instance, data=request.data)
        serializer.is_valid(raise_exception=True)
        self.perform_update(serializer)
        instance.increment_version()
        return Response(serializer.data)

    def get_etag(self, obj):
        return f'W/"{obj.version}"'
