func (c *ConcreteStrategyAdd) Execute(a, b int) int {
    return a + b
}

// ConcreteStrategySubtract is a concrete implementation of Strategy for subtraction.
type ConcreteStrategySubtract struct{}

// Execute subtracts b from a.
func (c *ConcreteStrategySubtract) Execute(a, b int) int {
    return a - b
}

// ConcreteStrategyMultiply is a concrete implementation of Strategy for multiplication.
type ConcreteStrategyMultiply struct{}

// Execute multiplies a and b.
func (c *ConcreteStrategyMultiply) Execute(a, b int) int {
    return a * b
}

// Context maintains a reference to a Strategy.
type Context struct {
    strategy Strategy
}

// SetStrategy sets the Strategy for the Context.
func (c *Context) SetStrategy(strategy Strategy) {
    c.strategy = strategy
}

// Execute executes the Strategy with the given values.
func (c *Context) Execute(a, b int) int {
    return c.strategy.Execute(a, b)
}

func main() {
    // Create context
    context := &Context{}

    // Use ConcreteStrategyAdd
    context.SetStrategy(&ConcreteStrategyAdd{})
    result := context.Execute(3, 4)
    fmt.Printf("Add: %d\n", result)

    // Use ConcreteStrategySubtract
    context.SetStrategy(&ConcreteStrategySubtract{})
    result = context.Execute(3, 4)
    fmt.Printf("Subtract: %d\n", result)

    // Use ConcreteStrategyMultiply
    context.SetStrategy(&ConcreteStrategyMultiply{})
    result = context.Execute(3, 4)
    fmt.Printf("Multiply: %d\n", result)
}
