using boost::asio::ip::tcp;

const int max_length = 1024;

void session(tcp::socket sock) {
    try {
        char data[max_length];

        while (true) {
            size_t length = sock.read_some(boost::asio::buffer(data, max_length));
            if (length > 0) {
                sock.write_some(boost::asio::buffer(data, length));
            } else {
                break;
            }
        }
    } catch (std::exception& e) {
        std::cerr << "Exception in thread: " << e.what() << std::endl;
    }
}

int main(int argc, char* argv[]) {
    try {
        if (argc!= 2) {
            std::cerr << "Usage: tcp_echo_server <port>" << std::endl;
            return 1;
        }

        boost::asio::io_context io_context;

        tcp::acceptor acceptor(io_context, tcp::endpoint(tcp::v4(), std::atoi(argv[1])));

        std::vector<std::thread> threads;
        while (true) {
            tcp::socket sock(io_context);
            acceptor.accept(sock);
            threads.emplace_back(std::thread(session, std::move(sock)));
        }

        for (auto& t : threads) {
            t.join();
        }
    } catch (std::exception& e) {
        std::cerr << "Exception: " << e.what() << std::endl;
    }

    return 0;
}

