func main() {
    if len(os.Args)!= 3 {
        fmt.Println("Usage: go run main.go <domain> <wordlist>\n")
        os.Exit(1)
    }

    domain := os.Args[1]
    wordlist := os.Args[2]

    var wg sync.WaitGroup

    file, err := os.Open(wordlist)
    if err!= nil {
        fmt.Printf("Failed to open wordlist: %s\n", err)
        os.Exit(1)
    }
    defer file.Close()

    scanner := bufio.NewScanner(file)
    for scanner.Scan() {
        subdomain := fmt.Sprintf("%s.%s", scanner.Text(), domain)
        wg.Add(1)
        go func(subdomain string) {
            defer wg.Done()
            if hasDNSRecord(subdomain) {
                fmt.Println(subdomain)
            }
        }(subdomain)
    }

    if err := scanner.Err(); err!= nil {
        fmt.Printf("Failed to read wordlist: %s\n", err)
        os.Exit(1)
    }

    wg.Wait()
}

func hasDNSRecord(domain string) bool {
    _, err := net.LookupHost(domain)
    return err == nil
}
