struct VendingMachine {
    state: Box<dyn State>,
}

trait State {
    fn insert_coin(&self, machine: &mut VendingMachine) -> String;
    fn select_item(&self, machine: &mut VendingMachine) -> String;
    fn dispense(&self, machine: &mut VendingMachine) -> String;
}

struct Idle;
impl State for Idle {
    fn insert_coin(&self, machine: &mut VendingMachine) -> String {
        machine.state = Box::new(Ready);
        "Coin inserted. Ready for selection.".to_string()
    }
    fn select_item(&self, _: &mut VendingMachine) -> String {
        "Please insert a coin first.".to_string()
    }
    fn dispense(&self, _: &mut VendingMachine) -> String {
        "Please insert a coin and select an item.".to_string()
    }
}

struct Ready;
impl State for Ready {
    fn insert_coin(&self, _: &mut VendingMachine) -> String {
        "Coin already inserted. Please select an item.".to_string()
    }
    fn select_item(&self, machine: &mut VendingMachine) -> String {
        machine.state = Box::new(Dispensing);
        "Item selected. Dispensing...".to_string()
    }
    fn dispense(&self, _: &mut VendingMachine) -> String {
        "Please select an item first.".to_string()
    }
}

struct Dispensing;
impl State for Dispensing {
    fn insert_coin(&self, _: &mut VendingMachine) -> String {
        "Please wait while dispensing.".to_string()
    }
    fn select_item(&self, _: &mut VendingMachine) -> String {
        "Please wait while dispensing.".to_string()
    }
    fn dispense(&self, machine: &mut VendingMachine) -> String {
        machine.state = Box::new(Idle);
        "Item dispensed. Machine is idle.".to_string()
    }
}

impl VendingMachine {
    fn new() -> Self {
        VendingMachine {
            state: Box::new(Idle),
        }
    }
    fn insert_coin(&mut self) -> String {
        self.state.insert_coin(self)
    }
    fn select_item(&mut self) -> String {
        self.state.select_item(self)
    }
    fn dispense(&mut self) -> String {
        self.state.dispense(self)
    }
}

fn main() {
    let mut machine = VendingMachine::new();
    println!("{}", machine.insert_coin());
    println!("{}", machine.select_item());
    println!("{}", machine.dispense());
