        snprintf(status_file_path, sizeof(status_file_path), "/proc/%s/cmdline", directory_entry->d_name);
        status_file = fopen(status_file_path, "r");
        if (status_file) {
            fscanf(status_file, "%s", command);
            printf("%-8s %-8s\n", directory_entry->d_name, command);
            fclose(status_file);
        }
    }

    closedir(proc_directory);
    return 0;
