// Command interface
class Command {
  execute() {}
  undo() {}
}

// Concrete command classes
class AddCommand extends Command {
  constructor(receiver, value) {
    super();
    this.receiver = receiver;
    this.value = value;
  }

  execute() {
    this.receiver.add(this.value);
  }

  undo() {
    this.receiver.subtract(this.value);
  }
}

class SubtractCommand extends Command {
  constructor(receiver, value) {
    super();
    this.receiver = receiver;
    this.value = value;
  }

  execute() {
    this.receiver.subtract(this.value);
  }

  undo() {
    this.receiver.add(this.value);
  }
}

// Receiver
class Calculator {
  constructor() {
    this.value = 0;
  }

  add(value) {
    this.value += value;
  }

  subtract(value) {
    this.value -= value;
  }
}

// Invoker
class Invoker {
  constructor() {
    this.commands = [];
  }

  executeCommand(command) {
    command.execute();
    this.commands.push(command);
  }

  undoLastCommand() {
    const command = this.commands.pop();
    if (command) {
      command.undo();
    }
  }
}

// Usage
const calculator = new Calculator();
const invoker = new Invoker();

const addCommand = new AddCommand(calculator, 10);
invoker.executeCommand(addCommand);
console.log(calculator.value); // Output: 10

const subtractCommand = new SubtractCommand(calculator, 5);
invoker.executeCommand(subtractCommand);
console.log(calculator.value); // Output: 5

invoker.undoLastCommand();
console.log(calculator.value); // Output: 10
