import sqlite3

class SafeDBConnectionIterator:
    def __init__(self, db_path):
        self.db_path = db_path
        self.connection = None
        self.cursor = None

    def __iter__(self):
        return self

    def __next__(self):
        if self.cursor is None:
            raise StopIteration
        row = self.cursor.fetchone()
        if row is None:
            self.cursor.close()
            self.connection.close()
            raise StopIteration
        return row

    def __enter__(self):
        self.connection = sqlite3.connect(self.db_path)
        self.cursor = self.connection.cursor()
        return self

    def __exit__(self, exc_type, exc_val, exc_tb):
        if self.cursor:
            self.cursor.close()
        if self.connection:
            self.connection.close()

# Usage example
with SafeDBConnectionIterator('example.db') as db_iterator:
    for row in db_iterator:
