package eventbus

import (
    "sync"
)

type EventBus struct {
    mu    sync.RWMutex
    subs  map[string][]func(string)
}

func NewEventBus() *EventBus {
    return &EventBus{
        subs: make(map[string][]func(string)),
    }
}

func (eb *EventBus) Publish(event string, data string) {
    eb.mu.RLock()
    defer eb.mu.RUnlock()

    for _, sub := range eb.subs[event] {
        sub(data)
    }
}

func (eb *EventBus) Subscribe(event string, sub func(string)) {
    eb.mu.Lock()
    defer eb.mu.Unlock()

    eb.subs[event] = append(eb.subs[event], sub)
}

func (eb *EventBus) Unsubscribe(event string, sub func(string)) {
    eb.mu.Lock()
    defer eb.mu.Unlock()

    for i, s := range eb.subs[event] {
        if s == sub {
            eb.subs[event] = append(eb.subs[event][:i], eb.subs[event][i+1:]...)
            break
        }
    }
}
