package main

import (
	"container/heap"
	"math"
)

type Edge struct {
	to, cost int
}

type State struct {
	node, cost int
}

type StateQueue []State

func (sq StateQueue) Len() int { return len(sq) }

func (sq StateQueue) Less(i, j int) bool {
	return sq[i].cost < sq[j].cost
}

func (sq StateQueue) Swap(i, j int) {
	sq[i], sq[j] = sq[j], sq[i]
}

func (sq *StateQueue) Push(x interface{}) {
	item := x.(State)
	*sq = append(*sq, item)
}

func (sq *StateQueue) Pop() interface{} {
	old := *sq
	n := len(old)
	x := old[n-1]
	*sq = old[0 : n-1]
	return x
}

func dijkstra(adjList map[int][]Edge, start int) map[int]int {
	dist := make(map[int]int)
	for node := range adjList {
		dist[node] = math.MaxInt32
	}
	dist[start] = 0

	pq := &StateQueue{}
	heap.Init(pq)
	heap.Push(pq, State{node: start, cost: 0})

	for pq.Len() > 0 {
		curr := heap.Pop(pq).(State)

		if curr.cost > dist[curr.node] {
			continue
		}

		for _, edge := range adjList[curr.node] {
			if curr.cost+edge.cost < dist[edge.to] {
				dist[edge.to] = curr.cost + edge.cost
				 heap.Push(pq, State{node: edge.to, cost: dist[edge.to]})
			}
		}
	}

	return dist
}

func main() {
	adjList := map[int][]Edge{
		0: {{to: 1, cost: 4}, {to: 2, cost: 1}},
		1: {{to: 3, cost: 1}},
		2: {{to: 1, cost: 2}, {to: 3, cost: 5}},
		3: {},
	}
	distances := dijkstra(adjList, 0)
	fmt.Println(distances)
}
