    if (index!== -1) {
      this.users[index] = {...this.users[index],...updatedUser };
      return this.users[index];
    }
    return null;
  }

  async delete(id) {
    const index = this.users.findIndex(user => user.id === id);
    if (index!== -1) {
      this.users.splice(index, 1);
      return true;
    }
    return false;
  }
}

