fn binary_search_rotated(arr: &[i32], target: i32) -> i32 {
    let mut left = 0;
    let mut right = arr.len() - 1;

    while left <= right {
        let mid = left + (right - left) / 2;

        if arr[mid] == target {
            return mid as i32;
        }

        if arr[left] <= arr[mid] {
            if target >= arr[left] && target < arr[mid] {
                right = mid - 1;
            } else {
                left = mid + 1;
            }
        } else {
            if target > arr[mid] && target <= arr[right] {
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
    }

    -1
}
