import (
    "math/rand"
    "time"
)

func RetryWithExponentialBackoff(initialInterval time.Duration, maxInterval time.Duration, maxRetries int, fn func() error) error {
    interval := initialInterval
    for i := 0; i < maxRetries; i++ {
        err := fn()
        if err == nil {
            return nil
        }

        // Add jitter to the interval
        jitter := time.Duration(rand.Float64() * float64(interval))
        interval += jitter

        // Exponential backoff
        interval *= 2
        if interval > maxInterval {
            interval = maxInterval
        }

        time.Sleep(interval)
    }
    return fmt.Errorf("max retries reached")
}
