package main

import (
	"net/http"
	"sync"
	"time"
	"golang.org/x/time/rate"
)

type rateLimiter struct {
	sync.RWMutex
	clients map[string]*rate.Limiter
}

func newRateLimiter() *rateLimiter {
	return &rateLimiter{
		clients: make(map[string]*rate.Limiter),
	}
}

func (r *rateLimiter) getLimiter(clientID string) *rate.Limiter {
	r.Lock()
	defer r.Unlock()

	limiter, exists := r.clients[clientID]
	if!exists {
		limiter = rate.NewLimiter(rate.Every(1*time.Minute), 60)
		r.clients[clientID] = limiter
	}
	return limiter
}

func rateLimitingMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		clientID := r.Header.Get("X-Client-ID")
		if clientID == "" {
			http.Error(w, "X-Client-ID header is required", http.StatusBadRequest)
			return
		}

		limiter := rateLimiter.getLimiter(clientID)
		allowed := limiter.Allow()
		if!allowed {
			http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
			return
		}

		next.ServeHTTP(w, r)
	})
}

func main() {
	http.Handle("/", rateLimitingMiddleware(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Write([]byte("Hello, World!"))
	})))
	http.ListenAndServe(":8080", nil)
}
