class TypedIterator:
    def __init__(self, elements, hint):
        self.elements = elements
        self.hint = hint
        self.index = 0

    def __iter__(self):
        return self

    def __next__(self):
        if self.index >= len(self.elements):
            raise StopIteration

        element = self.elements[self.index]
        self.index += 1

        if not isinstance(element, self.hint):
            raise TypeError(f"Expected type {self.hint.__name__}, but got {type(element).__name__}")

