// Run-length encoding function
char* encode(char* str) {
    int n = strlen(str);
    char* encoded = (char*)malloc(2 * n * sizeof(char));
    int i, j = 0;
    for (i = 0; i < n; i++) {
        int count = 1;
        while (i + 1 < n && str[i] == str[i + 1]) {
            count++;
            i++;
        }
        encoded[j++] = str[i];
        if (count > 1) {
            char countStr[10];
            sprintf(countStr, "%d", count);
            for (int k = 0; countStr[k]!= '\0'; k++)
                encoded[j++] = countStr[k];
        }
    }
    encoded[j] = '\0';
    return encoded;
}

// Run-length decoding function
char* decode(char* encoded) {
    int n = strlen(encoded);
    char* decoded = (char*)malloc(n * sizeof(char));
    int i, j = 0;
    for (i = 0; i < n; i++) {
        char ch = encoded[i];
        int count = 0;
        while (i + 1 < n && isdigit(encoded[i + 1])) {
            count = count * 10 + (encoded[i + 1] - '0');
            i++;
        }
        if (count == 0)
            count = 1;
        for (int k = 0; k < count; k++)
            decoded[j++] = ch;
    }
    decoded[j] = '\0';
    return decoded;
}

// Main function for testing
int main() {
    char str[] = "aabbbccccdddd";
    char* encoded = encode(str);
    printf("Encoded string: %s\n", encoded);
    char* decoded = decode(encoded);
    printf("Decoded string: %s\n", decoded);
    free(encoded);
    free(decoded);
    return 0;
