func SetSession(w http.ResponseWriter, username string) {
	value := map[string]string{
		"username": username,
	}
	encodedValue, err := cookieHandler.Encode("session", value)
	if err!= nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
	cookie := &http.Cookie{
		Name:     "session",
		Value:    encodedValue,
		Path:     "/",
		HttpOnly: true,
		SameSite: http.SameSiteStrictMode,
		MaxAge:   int(time.Hour.Seconds()),
	}
	http.SetCookie(w, cookie)
}

func GetSession(r *http.Request) (username string, err error) {
	cookie, err := r.Cookie("session")
	if err!= nil {
		return "", err
	}
	value := make(map[string]string)
	err = cookieHandler.Decode("session", cookie.Value, &value)
	if err!= nil {
		return "", err
	}
	return value["username"], nil
}

func DestroySession(w http.ResponseWriter) {
	cookie := &http.Cookie{
		Name:     "session",
		Value:    "",
		Path:     "/",
		HttpOnly: true,
		SameSite: http.SameSiteStrictMode,
		MaxAge:   -1,
	}
	http.SetCookie(w, cookie)
}

