func buildQuerySecure(userId int, status string) string {
    // Use a parameterized query to avoid SQL injection
    query := `SELECT * FROM users WHERE user_id = $1 AND status = $2`

    // Pass the user input as parameters separately
    db.Query(query, userId, status)

