function AStarSearch(grid, startNode, endNode) {
  const openList = [];
  const closedList = [];
  openList.push(startNode);

  while (openList.length > 0) {
    const currentNode = openList.reduce((lowest, node) => {
      return node.f < lowest.f? node : lowest;
    });

    if (currentNode === endNode) {
      return getPath(currentNode);
    }

    openList.splice(openList.indexOf(currentNode), 1);
    closedList.push(currentNode);

    const neighbors = getNeighbors(grid, currentNode);

    neighbors.forEach(neighbor => {
      if (closedList.includes(neighbor)) return;

      const tentativeG = currentNode.g + 1;

      if (!openList.includes(neighbor)) {
        openList.push(neighbor);
      } else if (tentativeG >= neighbor.g) {
        return;
      }

      neighbor.g = tentativeG;
      neighbor.h = heuristic(neighbor, endNode);
      neighbor.f = neighbor.g + neighbor.h;
      neighbor.parent = currentNode;
    });
  }

  return [];
}

function getPath(node) {
  const path = [];
  while (node) {
    path.push(node);
    node = node.parent;
  }
  return path.reverse();
}

function getNeighbors(grid, node) {
  const neighbors = [];
  const { x, y } = node;

  if (grid[y - 1] && grid[y - 1][x]) neighbors.push(grid[y - 1][x]);
  if (grid[y + 1] && grid[y + 1][x]) neighbors.push(grid[y + 1][x]);
  if (grid[y][x - 1]) neighbors.push(grid[y][x - 1]);
  if (grid[y][x + 1]) neighbors.push(grid[y][x + 1]);

  return neighbors;
}

function heuristic(nodeA, nodeB) {
  const dx = Math.abs(nodeA.x - nodeB.x);
  const dy = Math.abs(nodeA.y - nodeB.y);
  return dx + dy;
}
