#include <unordered_map>
#include <chrono>
#include <optional>
#include <thread>

using namespace std::chrono_literals;

template <typename Key, typename Value>
class KeyValueStore {
private:
    std::unordered_map<Key, Value> store;
    std::unordered_map<Key, std::chrono::steady_clock::time_point> expiry;
public:
    void insert(const Key& key, const Value& value, const std::chrono::milliseconds& ttl) {
        store[key] = value;
        expiry[key] = std::chrono::steady_clock::now() + ttl;
    }

    std::optional<Value> get(const Key& key) {
        if (contains(key)) {
            return store[key];
        }
        return std::nullopt;
    }

    bool contains(const Key& key) {
        if (store.find(key) == store.end()) {
            return false;
        }
        if (std::chrono::steady_clock::now() > expiry[key]) {
            store.erase(key);
            expiry.erase(key);
            return false;
        }
        return true;
    }
};

int main() {
    KeyValueStore<std::string, int> kvs;
    kvs.insert("key1", 42, 2000ms);
    kvs.insert("key2", 100, 5000ms);

    std::this_thread::sleep_for(1000ms);
    if (kvs.contains("key1")) {
        std::cout << "key1: " << kvs.get("key1").value() << std::endl;
    }

    std::this_thread::sleep_for(1500ms);
    if (kvs.contains("key1")) {
        std::cout << "key1: " << kvs.get("key1").value() << std::endl;
    } else {
        std::cout << "key1 has expired" << std::endl;
    }

    if (kvs.contains("key2")) {
        std::cout << "key2: " << kvs.get("key2").value() << std::endl;
    }

    return 0;
}

