use std::collections::HashMap;
use std::sync::{Arc, Mutex};

trait Subscriber<T> {
    fn notify(&self, event: &T);
}

struct EventBus<T> {
    subscribers: Arc<Mutex<HashMap<String, Vec<Box<dyn Subscriber<T>>>>>>,
}

impl<T> EventBus<T> {
    fn new() -> Self {
        EventBus {
            subscribers: Arc::new(Mutex::new(HashMap::new())),
        }
    }

    fn publish(&self, topic: &str, event: T) {
        let subscribers = self.subscribers.lock().unwrap();
        if let Some(subscribers) = subscribers.get(topic) {
            for subscriber in subscribers {
                subscriber.notify(&event);
            }
        }
    }

    fn register(&self, topic: &str, subscriber: Box<dyn Subscriber<T>>) {
        let mut subscribers = self.subscribers.lock().unwrap();
        subscribers.entry(topic.to_string()).or_default().push(subscriber);
    }
}
```
This Rust code defines a basic pub-sub event bus. The `EventBus` struct holds a `HashMap` that maps topics to vectors of subscribers. The `publish` method notifies all subscribers registered for a given topic when an event is published. The `register` method allows registering a subscriber for a specific topic.

```rust
struct HashMap<K, V> {
    buckets: Vec<Vec<(K, V)>>,
    size: usize,
}

impl<K: std::hash::Hash + Eq, V> HashMap<K, V> {
    fn new() -> Self {
        HashMap {
            buckets: vec![Vec::new(); 100],
            size: 0,
        }
    }

    fn insert(&mut self, key: K, value: V) {
        let index = self.get_index(&key);
        if let Some(pair) = self.buckets[index].iter_mut().find(|(k, _)| *k == key) {
            pair.1 = value;
        } else {
            self.buckets[index].push((key, value));
            self.size += 1;
        }
    }

    fn get(&self, key: &K) -> Option<&V> {
        let index = self.get_index(key);
        self.buckets[index].iter().find(|(k, _)| *k == key).map(|(_, v)| v)
    }

    fn remove(&mut self, key: &K) -> Option<V> {
        let index = self.get_index(key);
        if let Some(pos) = self.buckets[index].iter().position(|(k, _)| *k == *key) {
            self.size -= 1;
            Some(self.buckets[index].remove(pos).1)
        } else {
            None
        }
    }

    fn get_index(&self, key: &K) -> usize {
        let mut hasher = std::collections::hash_map::DefaultHasher::new();
        key.hash(&mut hasher);
        (hasher.finish() % self.buckets.len() as u64) as usize
    }
}
