#include <unordered_map>
#include <list>
#include <cstddef>

template<typename Key, typename Value>
class LRUCache {
public:
    LRUCache(size_t capacity) : _capacity(capacity) {}

    Value get(const Key& key) {
        auto it = _cache.find(key);
        if (it == _cache.end()) return Value();

        _lru.splice(_lru.begin(), _lru, it->second);
        return it->second->second;
    }

    void put(const Key& key, const Value& value) {
        auto it = _cache.find(key);
        if (it!= _cache.end()) {
            it->second->second = value;
            _lru.splice(_lru.begin(), _lru, it->second);
            return;
        }

        if (_cache.size() >= _capacity) {
            Key evicted_key = _lru.back().first;
            _lru.pop_back();
            _cache.erase(evicted_key);
        }

        _lru.emplace_front(key, value);
        _cache[key] = _lru.begin();
    }

private:
    size_t _capacity;
    std::list<std::pair<Key, Value>> _lru;
    std::unordered_map<Key, typename std::list<std::pair<Key, Value>>::iterator> _cache;
};

