#include <stdio.h>
#include <stdlib.h>

#define MAX 10

int queue[MAX];
int front = -1;
int rear = -1;

void enqueue(int element);
int dequeue();
void display();

int main() {
    int choice = 1, element;
    printf("Circular Queue Operations\n");
    while (choice!= 4) {
        printf("\n1.Enqueue\n2.Dequeue\n3.Display\n4.Quit\n");
        printf("Enter your choice: ");
        scanf("%d", &choice);
        switch (choice) {
            case 1:
                printf("\nEnter the element: ");
                scanf("%d", &element);
                enqueue(element);
                break;
            case 2:
                element = dequeue();
                if (element!= -1) {
                    printf("\nDeleted element is %d\n", element);
                }
                break;
            case 3:
                display();
                break;
            case 4:
                break;
            default:
                printf("\nInvalid choice\n");
        }
    }
    return 0;
}

void enqueue(int element) {
    if ((front == 0 && rear == MAX - 1) || (front == rear + 1)) {
        printf("\nQueue is full\n");
    } else {
        if (front == -1) {
            front = 0;
            rear = 0;
        } else if (rear == MAX - 1) {
            rear = 0;
        } else {
            rear++;
        }
        queue[rear] = element;
        printf("\nInserted element is %d\n", element);
    }
}

int dequeue() {
    int element;
    if (front == -1) {
        printf("\nQueue is empty\n");
        return -1;
    } else {
        element = queue[front];
        if (front == rear) {
            front = -1;
            rear = -1;
        } else if (front == MAX - 1) {
            front = 0;
        } else {
            front++;
        }
        return element;
    }
}

void display() {
    int i;
    if (front == -1) {
        printf("\nQueue is empty\n");
    } else {
        printf("\nQueue elements are: ");
        if (rear >= front) {
            for (i = front; i <= rear; i++) {
                printf("%d ", queue[i]);
            }
        } else {
            for (i = front; i < MAX; i++) {
                printf("%d ", queue[i]);
            }
            for (i = 0; i <= rear; i++) {
                printf("%d ", queue[i]);
            }
        }
    }
}

