import re


class InputValidator:
    def __init__(self):
        self.email_regex = r'^\w+([\.-]?\w+)*@\w+([\.-]?\w+)*(\.\w{2,3})+$'
        self.integer_regex = r'^\d+$'

    def validate_email(self, email):
        return re.match(self.email_regex, email) is not None

    def validate_integer(self, integer):
        return re.match(self.integer_regex, integer) is not None

    def sanitize_string(self, string):
        # Remove leading and trailing whitespace
        string = string.strip()
        # Remove any HTML tags
        string = re.sub(r'<[^>]*>', '', string)
        # Replace any script tags with empty string
        string = re.sub(r'<script.*?>.*?</script>', '', string, flags=re.DOTALL)
        # Escape single and double quotes to prevent SQL injection
        string = string.replace('"', '\"').replace('"', '"')
        return string

class Sanitizer:
    def __init__(self):
        self.validator = InputValidator()

    def sanitize_input(self, data):
        sanitized_data = {}
        for key, value in data.items():
            if isinstance(value, str):
                sanitized_data[key] = self.validator.sanitize_string(value)
            elif isinstance(value, int):
                sanitized_data[key] = value
            elif isinstance(value, dict):
                sanitized_data[key] = self.sanitize_input(value)
            elif isinstance(value, list):
                sanitized_data[key] = [self.sanitize_input(item) if isinstance(item, dict) else item for item in value]
            else:
                sanitized_data[key] = value
        return sanitized_data

def main():
    # Example usage
