class EventBus {
private:
    std::unordered_map<std::string, std::vector<std::function<void(const std::string&)>>> subscribers;

public:
    void publish(const std::string& topic, const std::string& payload) {
        auto it = subscribers.find(topic);
        if (it!= subscribers.end()) {
            for (const auto& callback : it->second) {
                callback(payload);
            }
        }
    }

    void subscribe(const std::string& topic, std::function<void(const std::string&)> callback) {
        subscribers[topic].push_back(callback);
    }
};

int main() {
