use std::collections::HashMap;

struct LruCache<K, V> {
    capacity: usize,
    map: HashMap<K, V>,
    usage: Vec<K>,
}

impl<K: Eq + std::hash::Hash + Copy, V> LruCache<K, V> {
    fn new(capacity: usize) -> Self {
        LruCache {
            capacity,
            map: HashMap::with_capacity(capacity),
            usage: Vec::with_capacity(capacity),
        }
    }

    fn get(&mut self, key: K) -> Option<&V> {
        if self.map.contains_key(&key) {
            self.usage.retain(|k| *k!= key);
            self.usage.push(key);
            self.map.get(&key)
        } else {
            None
        }
    }

    fn insert(&mut self, key: K, value: V) {
        if self.map.contains_key(&key) {
            self.usage.retain(|k| *k!= key);
        } else if self.map.len() >= self.capacity {
            let least_recently_used_key = self.usage.remove(0);
            self.map.remove(&least_recently_used_key);
        }
        self.map.insert(key, value);
        self.usage.push(key);
    }
}
