import time
from functools import wraps


def throttle(interval):
    def decorator(fn):
        last_call = 0

        @wraps(fn)
        def wrapper(*args, **kwargs):
            nonlocal last_call
            elapsed = time.time() - last_call
            if elapsed < interval:
                time.sleep(interval - elapsed)
            last_call = time.time()
            return fn(*args, **kwargs)

        return wrapper

    return decorator
