func levenshteinDistance(s1, s2 string) int {
    lenS1 := len(s1)
    lenS2 := len(s2)

    matrix := make([][]int, lenS1+1)
    for i := range matrix {
        matrix[i] = make([]int, lenS2+1)
    }

    for i := 0; i <= lenS1; i++ {
        matrix[i][0] = i
    }
    for j := 0; j <= lenS2; j++ {
        matrix[0][j] = j
    }

    for i := 1; i <= lenS1; i++ {
        for j := 1; j <= lenS2; j++ {
            cost := 1
            if s1[i-1] == s2[j-1] {
                cost = 0
            }

            matrix[i][j] = min(
                matrix[i-1][j]+1,
                matrix[i][j-1]+1,
                matrix[i-1][j-1]+cost,
            )
        }
    }

    return matrix[lenS1][lenS2]
}

func min(nums...int) int {
