use std::collections::HashMap;

gen enum Source {
    None,
    Self_,
    UnsafeInline,
    UnsafeEval,
    StrictDynamic,
    Host(String),
    Scheme(String),
    Nonce(String),
    Hash(String, String),
}

impl Source {
    fn to_string(&self) -> String {
        match self {
            Source::None => "'none'".to_string(),
            Source::Self_ => "'self'".to_string(),
            Source::UnsafeInline => "'unsafe-inline'".to_string(),
            Source::UnsafeEval => "'unsafe-eval'".to_string(),
            Source::StrictDynamic => "'strict-dynamic'".to_string(),
            Source::Host(host) => host.clone(),
            Source::Scheme(scheme) => scheme.clone(),
            Source::Nonce(nonce) => format!("'nonce-{}'", nonce),
            Source::Hash(algorithm, value) => format!("'{}-{}'", algorithm, value),
        }
    }
}

struct ContentSecurityPolicy {
    directives: HashMap<String, Vec<Source>>,
}

impl ContentSecurityPolicy {
    fn new() -> Self {
        ContentSecurityPolicy {
            directives: HashMap::new(),
        }
    }

    fn add_directive(&mut self, name: &str, source: Source) {
        let key = name.to_string();
        let sources = self.directives.entry(key).or_default();
        sources.push(source);
    }

    fn build(&self) -> String {
        let mut parts = Vec::new();
        for (directive, sources) in &self.directives {
            let values = sources.iter().map(Source::to_string).collect::<Vec<_>>().join(" ");
            parts.push(format!("{} {}", directive, values));
        }
        parts.join("; ")
    }
}

fn main() {
    let mut csp = ContentSecurityPolicy::new();
    csp.add_directive("default-src", Source::Self_);
    csp.add_directive("script-src", Source::Self_);
    csp.add_directive("script-src", Source::Nonce("random-nonce".to_string()));
    csp.add_directive("style-src", Source::Self_);
    csp.add_directive("style-src", Source::Hash("sha256".to_string(), "base64-encoded-hash".to_string()));
    csp.add_directive("img-src", Source::Self_);
    csp.add_directive("img-src", Source::Host("https://example.com".to_string()));

    let header_value = csp.build();
    println!("Content-Security-Policy: {}", header_value);
}
