#include <string>
#include <queue>
#include <sstream>

struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Codec {
public:
    std::string serialize(TreeNode* root) {
        if (root == nullptr) return "";

        std::queue<TreeNode*> q;
        q.push(root);
        std::string res = "";

        while (!q.empty()) {
            TreeNode* node = q.front();
            q.pop();
            if (node == nullptr) {
                res += "null,";
                continue;
            }
            res += std::to_string(node->val) + ",";
            q.push(node->left);
            q.push(node->right);
        }
        return res.substr(0, res.length() - 1);
    }

    TreeNode* deserialize(std::string data) {
        if (data.empty()) return nullptr;

        std::stringstream ss(data);
        std::string item;
        std::getline(ss, item, ',');
        TreeNode* root = new TreeNode(std::stoi(item));
        std::queue<TreeNode*> q;
        q.push(root);

        while (!q.empty()) {
            TreeNode* node = q.front();
            q.pop();

            std::getline(ss, item, ',');
            if (item!= "null") {
                node->left = new TreeNode(std::stoi(item));
                q.push(node->left);
            }

            std::getline(ss, item, ',');
            if (item!= "null") {
                node->right = new TreeNode(std::stoi(item));
                q.push(node->right);
            }
        }
        return root;
    }
};
