const express = require('express');
const path = require('path');
const fs = require('fs');

const app = express();

app.get('/download/:fileName', (req, res) => {
  const fileName = req.params.fileName;
  const basePath = path.join(__dirname, 'downloads');

  // Validate the fileName to prevent path traversal
  if (!/^[a-zA-Z0-9_-]+$/.test(fileName)) {
    return res.status(400).send('Invalid file name');
  }

  const filePath = path.join(basePath, fileName);

  // Check if the file exists
  fs.access(filePath, fs.constants.F_OK, (err) => {
    if (err) {
      return res.status(404).send('File not found');
    }

    // Send the file for download
    res.download(filePath, fileName);
  });
});

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});
```

The key changes made to fix the path traversal vulnerability are:

1. We validate the `fileName` parameter using a regular expression (`/^[a-zA-Z0-9_-]+$/`) to ensure it only contains alphanumeric characters, underscores, and hyphens. This prevents an attacker from using special characters like `..` to traverse directories.

2. We construct the `filePath` using `path.join(basePath, fileName)` instead of directly concatenating the `fileName` to the `basePath`. This ensures that the `filePath` is always within the intended `downloads` directory.

3. We check if the requested file exists using `fs.access()` before sending it for download. If the file doesn't exist, we return a 404 error. This prevents an attacker from accessing arbitrary files on the server.

By implementing these changes, the endpoint is now secure against path traversal attacks. The `fileName` is validated to prevent directory traversal, and the `filePath` is constructed securely to ensure it remains within the designated `downloads` directory. Additionally, checking for the file's existence prevents an attacker from accessing sensitive files outside the intended directory.

