std::vector<std::string> pingSweep(const std::string& subnet, int timeout) {
    std::vector<std::string> liveHosts;
    for (int i = 1; i < 255; ++i) {
        std::string ipAddress = subnet + "." + std::to_string(i);
        sockaddr_in address{};
        address.sin_family = AF_INET;
        address.sin_port = htons(0);
        inet_pton(AF_INET, ipAddress.c_str(), &address.sin_addr);

        int sock = socket(AF_INET, SOCK_STREAM, 0);
        timeval tv{};
        tv.tv_sec = timeout;
        setsockopt(sock, SOL_SOCKET, SO_RCVTIMEO, (char*)&tv, sizeof(timeval));

        if (connect(sock, (sockaddr*)&address, sizeof(address)) == 0) {
            liveHosts.push_back(ipAddress);
        }

        close(sock);
    }
    return liveHosts;
}

int main() {
    std::string subnet = "192.168.1";
    int timeout = 1;
    auto liveHosts = pingSweep(subnet, timeout);
    for (const auto& host : liveHosts) {
        std::cout << host << " is alive" << std::endl;
    }
    return 0;
