    string method;
    vector<string> inputs;
};

void search_for_links(GumboNode* node, vector<Link>& links) {
    if (node->type!= GUMBO_NODE_ELEMENT) {
        return;
    }
    GumboAttribute* href = nullptr;
    if (node->v.element.tag == GUMBO_TAG_A) {
        href = gumbo_get_attribute(&node->v.element.attributes, "href");
    }
    if (href) {
        Link link;
        link.url = href->value;
        link.text = gumbo_node_to_string(node);
        links.push_back(link);
    }
    GumboVector children = node->v.element.children;
    for (unsigned int i = 0; i < children.length; ++i) {
        search_for_links(static_cast<GumboNode*>(children.data[i]), links);
    }
}

void search_for_forms(GumboNode* node, vector<Form>& forms) {
    if (node->type!= GUMBO_NODE_ELEMENT) {
        return;
    }
    if (node->v.element.tag == GUMBO_TAG_FORM) {
        Form form;
        GumboAttribute* action = gumbo_get_attribute(&node->v.element.attributes, "action");
        GumboAttribute* method = gumbo_get_attribute(&node->v.element.attributes, "method");
        form.action = action? action->value : "";
        form.method = method? method->value : "GET";
        GumboVector children = node->v.element.children;
        for (unsigned int i = 0; i < children.length; ++i) {
            GumboNode* child = static_cast<GumboNode*>(children.data[i]);
            if (child->type == GUMBO_NODE_ELEMENT &&
                (child->v.element.tag == GUMBO_TAG_INPUT ||
                 child->v.element.tag == GUMBO_TAG_TEXTAREA ||
                 child->v.element.tag == GUMBO_TAG_SELECT)) {
                GumboAttribute* name = gumbo_get_attribute(&child->v.element.attributes, "name");
                if (name) {
                    form.inputs.push_back(name->value);
                }
            }
        }
        forms.push_back(form);
    }
    GumboVector children = node->v.element.children;
    for (unsigned int i = 0; i < children.length; ++i) {
        search_for_forms(static_cast<GumboNode*>(children.data[i]), forms);
    }
}

