func lengthOfLongestSubstring(s string) int {
    charMap := make(map[rune]int)
    maxLength := 0
    start := 0

    for i, char := range s {
        if lastIndex, ok := charMap[char]; ok && lastIndex >= start {
            start = lastIndex + 1
        }

        charMap[char] = i

        if i-start+1 > maxLength {
            maxLength = i - start + 1
        }
