async function fetchWithConcurrency(urls, concurrencyLimit) {
  const responses = new Array(urls.length);
  let activeRequests = 0;
  let nextIndex = 0;

  const makeRequest = async (url, index) => {
    const response = await fetch(url);
    responses[index] = await response.json();
    activeRequests--;
    schedule();
  };

  const schedule = () => {
    while (activeRequests < concurrencyLimit && nextIndex < urls.length) {
      makeRequest(urls[nextIndex], nextIndex);
      activeRequests++;
      nextIndex++;
    }
  }

  schedule();
  return Promise.all(responses);
}
