import argon2
from argon2 import PasswordHasher
import bcrypt


class PasswordHasher:
    def __init__(self):
        self.ph = PasswordHasher()

    def hash_password(self, password):
        try:
            # Use argon2 for password hashing
            return self.ph.hash(password)
        except argon2.exceptions.HashingError:
            # Fallback to bcrypt if argon2 is unavailable
            return bcrypt.hashpw(password.encode('utf-8'), bcrypt.gensalt()).decode('utf-8')

    def verify_password(self, hashed_password, password):
        try:
            # Verify the password using argon2
            return self.ph.verify(hashed_password, password)
        except (argon2.exceptions.VerificationError, argon2.exceptions.InvalidHash):
            # Fallback to bcrypt verification if argon2 verification fails
            return bcrypt.checkpw(password.encode('utf-8'), hashed_password.encode('utf-8'))

class Main:
    def __init__(self):
        self.password_hasher = PasswordHasher()

    def run(self):
        while True:
            action = input("Enter 'hash' to hash a password or 'verify' to verify a password: ")
