class UnionFind {
    private $ids;
    private $count;

    public function __construct($n) {
        $this->count = $n;
        $this->ids = range(0, $n-1);
    }

    public function find($p) {
        while ($p!= $this->ids[$p]) {
            $this->ids[$p] = $this->ids[$this->ids[$p]];
            $p = $this->ids[$p];
        }
        return $p;
    }

    public function union($p, $q) {
        $rootP = $this->find($p);
        $rootQ = $this->find($q);
        if ($rootP == $rootQ) return;
        $this->ids[$rootP] = $rootQ;
        $this->count--;
    }

    public function isConnected($p, $q) {
        return $this->find($p) == $this->find($q);
    }

    public function count() {
        return $this->count;
    }
}
