fn retry_with_exponential_backoff<F, T, E>(initial_interval: u64, max_interval: u64, max_retries: usize, mut operation: F) -> Result<T, E>
where
    F: FnMut() -> Result<T, E>,
{
    let mut interval = initial_interval;
    let mut retries = 0;

    loop {
        match operation() {
            Ok(result) => return Ok(result),
            Err(err) => {
                retries += 1;
                if retries > max_retries {
                    return Err(err);
                }

                // Calculate exponential backoff with jitter
                let jitter = rand::random::<f64>() * (interval as f64);
                interval = (interval as f64 * 2.0 + jitter) as u64;
                if interval > max_interval {
                    interval = max_interval;
                }

                std::thread::sleep(std::time::Duration::from_millis(interval));
            }
        }
    }
}
