// Define the strategy trait
trait SortStrategy {
    fn sort(&self, data: &mut Vec<i32>);
}

// Implement the ascending sort strategy
struct AscendingSort;
impl SortStrategy for AscendingSort {
    fn sort(&self, data: &mut Vec<i32>) {
        data.sort();
    }
}

// Implement the descending sort strategy
struct DescendingSort;
impl SortStrategy for DescendingSort {
    fn sort(&self, data: &mut Vec<i32>) {
        data.sort_by(|a, b| b.cmp(a));
    }
}

// Define the context struct
struct Sorter {
    strategy: Box<dyn SortStrategy>,
}

impl Sorter {
    fn new(strategy: Box<dyn SortStrategy>) -> Self {
        Sorter { strategy }
    }

    fn set_strategy(&mut self, strategy: Box<dyn SortStrategy>) {
        self.strategy = strategy;
    }

    fn sort(&self, data: &mut Vec<i32>) {
        self.strategy.sort(data);
    }
}

fn main() {
    let mut data = vec![5, 2, 4, 3, 1];

    let mut sorter = Sorter::new(Box::new(AscendingSort));
    sorter.sort(&mut data);
    println!("Sorted in ascending order: {:?}", data);

    sorter.set_strategy(Box::new(DescendingSort));
    sorter.sort(&mut data);
    println!("Sorted in descending order: {:?}", data);
}
