fn bfs(maze: &Vec<Vec<i32>>, start: (i32, i32), end: (i32, i32)) -> Option<Vec<(i32, i32)>> {
    let rows = maze.len() as i32;
    let cols = maze[0].len() as i32;
    let mut queue = std::collections::VecDeque::new();
    let mut visited = vec![vec![false; cols as usize]; rows as usize];
    let mut prev = vec![vec![(0, 0); cols as usize]; rows as usize];

    queue.push_back(start);
    visited[start.0 as usize][start.1 as usize] = true;

    while let Some((row, col)) = queue.pop_front() {
        if (row, col) == end {
            let mut path = Vec::new();
            let mut current = end;
            while current!= start {
                path.push(current);
                current = prev[current.0 as usize][current.1 as usize];
            }
            path.push(start);
            path.reverse();
            return Some(path);
        }

        for (dr, dc) in [(-1, 0), (1, 0), (0, -1), (0, 1)].iter() {
            let new_row = row + dr;
            let new_col = col + dc;
            if new_row >= 0 && new_row < rows && new_col >= 0 && new_col < cols {
                if!visited[new_row as usize][new_col as usize] && maze[new_row as usize][new_col as usize] == 0 {
                    queue.push_back((new_row, new_col));
                    visited[new_row as usize][new_col as usize] = true;
                    prev[new_row as usize][new_col as usize] = (row, col);
                }
            }
        }
    }

    None
}
