package main

import "fmt"

type SegmentTree struct {
    tree []int
    n    int
}

func (st *SegmentTree) buildTree(arr []int, node, start, end int) {
    if start == end {
        st.tree[node] = arr[start]
        return
    }

    mid := (start + end) / 2
    st.buildTree(arr, 2*node, start, mid)
    st.buildTree(arr, 2*node+1, mid+1, end)

    st.tree[node] = st.tree[2*node] + st.tree[2*node+1]
}

func (st *SegmentTree) queryTree(node, start, end, left, right int) int {
    if left > end || right < start {
        return 0
    }

    if left <= start && end <= right {
        return st.tree[node]
    }

    mid := (start + end) / 2
    leftSum := st.queryTree(2*node, start, mid, left, right)
    rightSum := st.queryTree(2*node+1, mid+1, end, left, right)

    return leftSum + rightSum
}

func newSegmentTree(arr []int) *SegmentTree {
    n := len(arr)
    tree := make([]int, 4*n)
    st := &SegmentTree{
        tree: tree,
        n:    n,
    }
    st.buildTree(arr, 1, 0, n-1)
    return st
}

func main() {
    arr := []int{1, 3, 5, 7, 9, 11}
    st := newSegmentTree(arr)

    left := 1
    right := 4
    sum := st.queryTree(1, 0, st.n-1, left, right)
    fmt.Printf("Sum of elements from index %d to %d is %d\n", left, right, sum)
}
