package main

import (
    "fmt"
    "sync"
    "time"
)

type TokenBucket struct {
    maxTokens      int
    tokenRefresh   int
    interval       time.Duration
    availableTokens int
    mu             sync.Mutex
}

func NewTokenBucket(maxTokens, tokenRefresh int, interval time.Duration) *TokenBucket {
    return &TokenBucket{
        maxTokens:      maxTokens,
        tokenRefresh:   tokenRefresh,
        interval:       interval,
        availableTokens: maxTokens,
    }
}

func (tb *TokenBucket) Allow(requestTokens int) bool {
    tb.mu.Lock()
    defer tb.mu.Unlock()

    if tb.availableTokens >= requestTokens {
        tb.availableTokens -= requestTokens
        return true
    }
    return false
}

func (tb *TokenBucket) Start() {
    ticker := time.NewTicker(tb.interval)
    for {
        <-ticker.C
        tb.mu.Lock()
        tb.availableTokens += tb.tokenRefresh
        if tb.availableTokens > tb.maxTokens {
            tb.availableTokens = tb.maxTokens
        }
        tb.mu.Unlock()
    }
}

func main() {
    tb := NewTokenBucket(100, 10, time.Second)
    go tb.Start()

    for i := 0; i < 100; i++ {
        if tb.Allow(1) {
            fmt.Println("Request allowed")
        } else {
            fmt.Println("Request blocked")
        }
        time.Sleep(100 * time.Millisecond)
    }
}
