template <typename T>
class DoublyLinkedList {
private:
    Node<T>* head;

public:
    DoublyLinkedList() : head(nullptr) {}

    void insertAtBeginning(T value) {
        Node<T>* newNode = new Node<T>(value);
        if (head == nullptr) {
            head = newNode;
        } else {
            newNode->next = head;
            head->prev = newNode;
            head = newNode;
        }
    }

    void deleteByValue(T value) {
        if (head == nullptr)
            return;

        Node<T>* current = head;
        while (current!= nullptr) {
            if (current->data == value) {
                if (current == head)
                    head = current->next;
                if (current->prev!= nullptr)
                    current->prev->next = current->next;
                if (current->next!= nullptr)
                    current->next->prev = current->prev;
                delete current;
                return;
            }
            current = current->next;
        }
    }

    void reverse() {
        Node<T>* current = head;
        Node<T>* temp = nullptr;
        while (current!= nullptr) {
            temp = current->prev;
            current->prev = current->next;
            current->next = temp;
            current = current->prev;
        }
        if (temp!= nullptr)
            head = temp->prev;
    }

    void display() {
        Node<T>* current = head;
        while (current!= nullptr) {
            std::cout << current->data << " ";
            current = current->next;
        }
        std::cout << std::endl;
    }
};

