package main

import "fmt"

type MinHeap struct {
    data []int
}

func (h *MinHeap) Insert(value int) {
    h.data = append(h.data, value)
    h.bubbleUp(len(h.data) - 1)
}

func (h *MinHeap) ExtractMin() int {
    if len(h.data) == 0 {
        panic("Cannot extract from an empty heap.")
    }
    min := h.data[0]
    last := h.data[len(h.data)-1]
    h.data = h.data[:len(h.data)-1]
    if len(h.data) > 0 {
        h.data[0] = last
        h.bubbleDown(0)
    }
    return min
}

func (h *MinHeap) Peek() int {
    if len(h.data) == 0 {
        panic("Cannot peek an empty heap.")
    }
    return h.data[0]
}

func (h *MinHeap) Size() int {
    return len(h.data)
}

func (h *MinHeap) bubbleUp(index int) {
    for index > 0 {
        parentIndex := (index - 1) / 2
        if h.data[parentIndex] <= h.data[index] {
            break
        }
        h.data[parentIndex], h.data[index] = h.data[index], h.data[parentIndex]
        index = parentIndex
    }
}

func (h *MinHeap) bubbleDown(index int) {
    for {
        leftChildIndex := 2*index + 1
        rightChildIndex := 2*index + 2
        minIndex := index

        if leftChildIndex < len(h.data) && h.data[leftChildIndex] < h.data[minIndex] {
            minIndex = leftChildIndex
        }

        if rightChildIndex < len(h.data) && h.data[rightChildIndex] < h.data[minIndex] {
            minIndex = rightChildIndex
        }

        if minIndex == index {
            break
        }

        h.data[index], h.data[minIndex] = h.data[minIndex], h.data[index]
        index = minIndex
    }
}

func main() {
    heap := &MinHeap{}
    heap.Insert(5)
    heap.Insert(3)
    heap.Insert(7)
    fmt.Println(heap.Peek()) // 3
    fmt.Println(heap.Size())  // 3
    fmt.Println(heap.ExtractMin()) // 3
    fmt.Println(heap.Peek()) // 5
}
