#define MAP_SIZE 100

typedef struct _Node {
    char* key;
    int value;
    struct _Node* next;
} Node;

Node* createNode(const char* key, int value) {
    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->key = strdup(key);
    newNode->value = value;
    newNode->next = NULL;
    return newNode;
}

int hash(const char* key) {
    int sum = 0;
    for (int i = 0; key[i]!= '\0'; i++) {
        sum += key[i];
    }
    return sum % MAP_SIZE;
}

void insert(Node** map, const char* key, int value) {
    int index = hash(key);
    Node* newNode = createNode(key, value);

    if (map[index] == NULL) {
        map[index] = newNode;
    } else {
        Node* current = map[index];
        while (current->next!= NULL) {
            current = current->next;
        }
        current->next = newNode;
    }
}

int search(Node** map, const char* key) {
    int index = hash(key);
    if (map[index]!= NULL) {
        Node* current = map[index];
        while (current!= NULL) {
            if (strcmp(current->key, key) == 0) {
                return current->value;
            }
            current = current->next;
        }
    }
    return -1;  // Key not found
}

void delete(Node** map, const char* key) {
    int index = hash(key);
    if (map[index]!= NULL) {
        Node* current = map[index];
        Node* prev = NULL;

        while (current!= NULL) {
            if (strcmp(current->key, key) == 0) {
                if (prev == NULL) {
                    map[index] = current->next;
                } else {
                    prev->next = current->next;
                }
                free(current->key);
                free(current);
                return;
            }
            prev = current;
            current = current->next;
        }
    }
}

int main() {
    Node* hash_map[MAP_SIZE] = {NULL};

    insert(hash_map, "apple", 5);
    insert(hash_map, "banana", 10);
    insert(hash_map, "orange", 7);

