import base64
import binascii
import re

def detect_and_decode(data):
    if is_base64(data):
        return base64.b64decode(data).decode()
    elif is_hex(data):
        return binascii.unhexlify(data).decode()
    elif is_rot13(data):
        return rot13_decode(data)
    else:
        return 'Unknown encoding'

def is_base64(data):
    try:
        if base64.b64encode(base64.b64decode(data)).decode() == data:
            return True
    except binascii.Error:
        pass
    return False

def is_hex(data):
    if len(data) % 2 == 0 and re.fullmatch(r'^[0-9a-fA-F]+$', data):
        return True
    return False

def is_rot13(data):
    if re.fullmatch(r'^[a-zA-Z]+$', data):
        return True
    return False

def rot13_decode(data):
    return data.translate(str.maketrans('abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ', 'nopqrstuvwxyzabcdefghijklmNOPQRSTUVWXYZABCDEFGHIJKLM'))

