import "fmt"

type CircularBuffer struct {
    buffer []int
    size   int
    head   int
    tail   int
    count  int
}

func NewCircularBuffer(size int) *CircularBuffer {
    return &CircularBuffer{
        buffer: make([]int, size),
        size:   size,
        head:   0,
        tail:   0,
        count:  0,
    }
}

func (cb *CircularBuffer) Add(element int) {
    if cb.count == cb.size {
        cb.head = (cb.head + 1) % cb.size
    } else {
        cb.count++
    }
    cb.buffer[cb.tail] = element
    cb.tail = (cb.tail + 1) % cb.size
}

func (cb *CircularBuffer) Get(index int) int {
    if index >= cb.count || index < 0 {
        panic("Index out of bounds")
    }
    return cb.buffer[(cb.head+index)%cb.size]
}

func main() {
    cb := NewCircularBuffer(5)
    cb.Add(1)
    cb.Add(2)
    cb.Add(3)
    cb.Add(4)
