def exponential_backoff_with_jitter(operation, max_retries, initial_delay):
    retries = 0
    delay = initial_delay
    while retries < max_retries:
        try:
            return operation()
        except Exception as e:
            retries += 1
            if retries == max_retries:
                raise e
            jitter = random.uniform(0, min(0.2 * delay, 1))
