class LinkedListNode {
  constructor(key, value) {
    this.key = key;
    this.value = value;
    this.next = null;
  }
}

class HashMap {
  constructor(size = 10) {
    this.size = size;
    this.storage = new Array(size).fill(null);
  }

  hash(key) {
    let total = 0;
    for (let i = 0; i < key.length; i++) {
      total += key.charCodeAt(i);
    }
    return total % this.size;
  }

  put(key, value) {
    const index = this.hash(key);
    if (!this.storage[index]) {
      this.storage[index] = new LinkedListNode(key, value);
    } else {
      let currentNode = this.storage[index];
      while (currentNode) {
        if (currentNode.key === key) {
          currentNode.value = value;
          return;
        }
        if (!currentNode.next) {
          currentNode.next = new LinkedListNode(key, value);
          return;
        }
        currentNode = currentNode.next;
      }
    }
  }

  get(key) {
    const index = this.hash(key);
    let currentNode = this.storage[index];
    while (currentNode) {
      if (currentNode.key === key) {
        return currentNode.value;
      }
      currentNode = currentNode.next;
    }
    return undefined;
  }

  remove(key) {
    const index = this.hash(key);
    let currentNode = this.storage[index];
    if (!currentNode) {
      return;
    }
    if (currentNode.key === key) {
      this.storage[index] = currentNode.next;
      return;
    }
    let prevNode = currentNode;
    currentNode = currentNode.next;
    while (currentNode) {
      if (currentNode.key === key) {
        prevNode.next = currentNode.next;
        return;
      }
      prevNode = currentNode;
      currentNode = currentNode.next;
    }
  }

  size() {
    let count = 0;
    for (let i = 0; i < this.storage.length; i++) {
      if (this.storage[i]) {
        let currentNode = this.storage[i];
        while (currentNode) {
          count++;
          currentNode = currentNode.next;
        }
      }
    }
    return count;
  }
}
