        let mut conn = self.pool.get_conn().unwrap();
        conn.prep_exec(query, params).unwrap().affected_rows()
    }

    pub fn delete(&self, query: &str, params: &[Value]) -> u64 {
        let mut conn = self.pool.get_conn().unwrap();
        conn.prep_exec(query, params).unwrap().affected_rows()
    }
