string getFileHash(const string &filePath, size_t chunkSize) {
    ifstream file(filePath, ios::binary);
    if (!file) {
        cerr << "Failed to open file: " << filePath << endl;
        return "";
    }
    string chunk(chunkSize, 0);
    string hash;
    while (file.read(&chunk[0], chunkSize)) {
        chunk.resize(file.gcount());
        hash = sha256(hash + chunk);
    }
    return hash;
}

int main(int argc, char *argv[]) {
    if (argc!= 2) {
        cerr << "Usage: " << argv[0] << " <file_path>" << endl;
        return 1;
    }
    string filePath = argv[1];
    size_t chunkSize = 1024 * 1024; // 1 MB
    string hash = getFileHash(filePath, chunkSize);
    cout << "SHA-256 hash: " << hash << endl;
    return 0;
