use actix_multipart::Multipart;
use actix_web::{post, web, HttpResponse, Responder};
use std::fs;
use uuid::Uuid;

#[post("/upload")]
async fn upload(mut payload: Multipart) -> impl Responder {
    if let Some(item) = payload.next().await {
        let mut field = item.unwrap();
        let content_type = field.content_type().unwrap();
        let file_extension = content_type.subtype();

        // Generate a secure, unique filename using a UUID
        let secure_filename = format!("{}.{}", Uuid::new_v4(), file_extension);

        // Save the uploaded file with the secure filename
        let filepath = format!("uploads/{}", secure_filename);
        let mut f = web::block(|| fs::File::create(filepath))
           .await
           .unwrap();
        while let Some(chunk) = field.next().await {
            let data = chunk.unwrap();
            f = web::block(move || f.write_all(&data).map(|_| f))
               .await
               .unwrap();
        }
    }

    HttpResponse::Ok().body("File uploaded successfully")
}
