struct SegmentTree {
    tree: Vec<i32>,
    n: usize,
}

impl SegmentTree {
    fn build(nums: &Vec<i32>) -> Self {
        let n = nums.len();
        let mut tree = vec![0; 4 * n];
        Self::build_helper(&mut tree, nums, 0, 0, n - 1);
        SegmentTree { tree, n }
    }

    fn build_helper(tree: &mut Vec<i32>, nums: &Vec<i32>, node: usize, start: usize, end: usize) -> i32 {
        if start == end {
            tree[node] = nums[start];
            return nums[start];
        }
        let mid = start + (end - start) / 2;
        let left_sum = Self::build_helper(tree, nums, 2 * node + 1, start, mid);
        let right_sum = Self::build_helper(tree, nums, 2 * node + 2, mid + 1, end);
        tree[node] = left_sum + right_sum;
        tree[node]
    }

    fn update(&mut self, index: usize, value: i32) {
        self.update_helper(0, 0, self.n - 1, index, value);
    }

    fn update_helper(&mut self, node: usize, start: usize, end: usize, index: usize, value: i32) {
        if start == end {
            self.tree[node] = value;
            return;
        }
        let mid = start + (end - start) / 2;
        if index <= mid {
            self.update_helper(2 * node + 1, start, mid, index, value);
        } else {
            self.update_helper(2 * node + 2, mid + 1, end, index, value);
        }
        self.tree[node] = self.tree[2 * node + 1] + self.tree[2 * node + 2];
    }

    fn range_sum(&self, left: usize, right: usize) -> i32 {
        self.range_sum_helper(0, 0, self.n - 1, left, right)
    }

    fn range_sum_helper(&self, node: usize, start: usize, end: usize, left: usize, right: usize) -> i32 {
        if left <= start && end <= right {
            return self.tree[node];
        }
        let mid = start + (end - start) / 2;
        let mut sum = 0;
        if left <= mid {
            sum += self.range_sum_helper(2 * node + 1, start, mid, left, right);
        }
        if right > mid {
            sum += self.range_sum_helper(2 * node + 2, mid + 1, end, left, right);
        }
        sum
    }
}
