use std::cmp::Ordering;
use std::collections::BinaryHeap;

#[derive(Copy, Clone, Eq, PartialEq)]
struct Node {
    position: (usize, usize),
    cost: usize,
    heuristic: usize,
}

impl Ord for Node {
    fn cmp(&self, other: &Self) -> Ordering {
        (other.cost + other.heuristic).cmp(&(self.cost + self.heuristic))
    }
}

impl PartialOrd for Node {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

fn heuristic(a: (usize, usize), b: (usize, usize)) -> usize {
    ((a.0 as i32 - b.0 as i32).abs() + (a.1 as i32 - b.1 as i32).abs()) as usize
}

fn astar(map: &Vec<Vec<usize>>, start: (usize, usize), goal: (usize, usize)) -> Option<usize> {
    let mut open_set = BinaryHeap::new();
    open_set.push(Node {
        position: start,
        cost: 0,
        heuristic: heuristic(start, goal),
    });

    let mut came_from = vec![vec![(0, 0); map[0].len()]; map.len()];
    let mut g_score = vec![vec![usize::MAX; map[0].len()]; map.len()];
    g_score[start.0][start.1] = 0;

    while let Some(current) = open_set.pop() {
        if current.position == goal {
            return Some(g_score[goal.0][goal.1]);
        }

        let neighbors = [
            (current.position.0 as i32 - 1, current.position.1 as i32),
            (current.position.0 as i32 + 1, current.position.1 as i32),
            (current.position.0 as i32, current.position.1 as i32 - 1),
            (current.position.0 as i32, current.position.1 as i32 + 1),
        ];

        for neighbor in &neighbors {
            if neighbor.0 < 0 || neighbor.1 < 0 {
                continue;
            }
            let neighbor = (neighbor.0 as usize, neighbor.1 as usize);
            if neighbor.0 >= map.len() || neighbor.1 >= map[0].len() {
                continue;
            }

            let tentative_g_score = g_score[current.position.0][current.position.1] + map[neighbor.0][neighbor.1];

            if tentative_g_score < g_score[neighbor.0][neighbor.1] {
                came_from[neighbor.0][neighbor.1] = current.position;
                g_score[neighbor.0][neighbor.1] = tentative_g_score;
                let f_score = tentative_g_score + heuristic(neighbor, goal);

                open_set.push(Node {
                    position: neighbor,
                    cost: tentative_g_score,
                    heuristic: f_score,
                });
            }
        }
    }

    None
}
