function dijkstra(graph, start, end) {
  const distances = {};
  const previous = {};
  const pq = new PriorityQueue();

  for (const vertex in graph) {
    distances[vertex] = Infinity;
    previous[vertex] = null;
  }
  distances[start] = 0;
  pq.enqueue(start, 0);

  while (!pq.isEmpty()) {
    const current = pq.dequeue();

    if (current === end) {
      const path = [];
      while (previous[current]) {
        path.push(current);
        current = previous[current];
      }
      path.push(start);
      path.reverse();

      return {
        distance: distances[end],
        path: path
      };
    }

    for (const neighbor in graph[current]) {
      const distance = graph[current][neighbor] + distances[current];
      if (distance < distances[neighbor]) {
        distances[neighbor] = distance;
        previous[neighbor] = current;
        pq.enqueue(neighbor, distance);
      }
    }
  }
}

// Priority queue implementation
function PriorityQueue() {
  this.collection = [];
}

PriorityQueue.prototype.enqueue = function(element, priority) {
  this.collection.push({element, priority});
}

PriorityQueue.prototype.dequeue = function() {
  if (this.isEmpty()) {
    return;
  }
  let highestPriority = 0;
  for (let i = 1; i < this.collection.length; i++) {
    if (this.collection[i].priority < this.collection[highestPriority].priority) {
      highestPriority = i;
    }
  }
  const item = this.collection[highestPriority].element;
  this.collection.splice(highestPriority, 1);
  return item;
}

PriorityQueue.prototype.isEmpty = function() {
  return (this.collection.length === 0);
}
