use std::time::{Duration, Instant};
use std::thread;

pub fn debounce<F: FnMut()>(mut callback: F, delay: Duration) -> impl FnMut() {
    let mut last_call = Instant::now() - delay;
    move || {
        let now = Instant::now();
        if now.duration_since(last_call) >= delay {
            callback();
            last_call = now;
        }
    }
}

pub fn throttle<F: FnMut()>(mut callback: F, period: Duration) -> impl FnMut() {
    let mut last_call = Instant::now() - period;
    move || {
        let now = Instant::now();
        if now.duration_since(last_call) >= period {
            callback();
            last_call = now;
        }
    }
}
