import java.util.*;

class Graph {
    public static List<Integer> topologicalSort(HashMap<Integer, List<Integer>> graph) {
        List<Integer> result = new ArrayList<>();
        HashSet<Integer> visited = new HashSet<>();
        HashSet<Integer> recursionStack = new HashSet<>();

        for (Integer node : graph.keySet()) {
            if (!visited.contains(node)) {
                if (isCyclic(graph, node, visited, recursionStack, result)) {
                    return new ArrayList<>(); // return empty list if cyclic
                }
            }
        }

        Collections.reverse(result);
        return result;
    }

    private static boolean isCyclic(HashMap<Integer, List<Integer>> graph, Integer node,
                                   HashSet<Integer> visited, HashSet<Integer> recursionStack,
                                   List<Integer> result) {
        visited.add(node);
        recursionStack.add(node);

        for (Integer neighbor : graph.getOrDefault(node, new ArrayList<>())) {
            if (!visited.contains(neighbor)) {
                if (isCyclic(graph, neighbor, visited, recursionStack, result)) {
                    return true;
                }
            } else if (recursionStack.contains(neighbor)) {
                return true;
            }
        }

        recursionStack.remove(node);
        result.add(node);
        return false;
    }
}
