use std::path::PathBuf;

fn main() -> io::Result<()> {
    let base_dir = PathBuf::from("/var/myapp/data");
    let user_path = PathBuf::from("../../../../etc/passwd");
    let joined_path = base_dir.join(&user_path);
    let canonical_path = joined_path.canonicalize()?;

    if!canonical_path.starts_with(&base_dir) {
        return Err(io::Error::new(
            io::ErrorKind::PermissionDenied,
            "Attempted path traversal",
        ));
    }

