use std::collections::{BinaryHeap, HashMap, HashSet};
use std::cmp::Ordering;

#[derive(Eq, PartialEq, Debug)]
struct Node<T> {
    vertex: T,
    weight: usize,
}

impl<T: Ord> Ord for Node<T> {
    fn cmp(&self, other: &Self) -> Ordering {
        other.weight.cmp(&self.weight)
    }
}

impl<T: Ord> PartialOrd for Node<T> {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

fn dijkstra<T: Eq + std::hash::Hash + Copy>(
    graph: &HashMap<T, HashMap<T, usize>>,
    start: T,
    end: T,
) -> (Vec<T>, usize) {
    let mut dist: HashMap<T, usize> = graph.keys().map(|k| (*k, usize::MAX)).collect();
    let mut prev: HashMap<T, Option<T>> = graph.keys().map(|k| (*k, None)).collect();
    let mut pq: BinaryHeap<Node<T>> = BinaryHeap::new();
    let mut visited: HashSet<T> = HashSet::new();

    dist.insert(start, 0);
    pq.push(Node { vertex: start, weight: 0 });

    while let Some(current) = pq.pop() {
        if current.vertex == end {
            break;
        }

        if!visited.insert(current.vertex) {
            continue;
        }

        if let Some(neighbors) = graph.get(&current.vertex) {
            for (neighbor, weight) in neighbors {
                let new_weight = dist[&current.vertex] + weight;
                if new_weight < dist[neighbor] {
                    dist.insert(*neighbor, new_weight);
                    prev.insert(*neighbor, Some(current.vertex));
                    pq.push(Node {
                        vertex: *neighbor,
                        weight: new_weight,
                    });
                }
            }
        }
    }

    let mut path = Vec::new();
    let mut current = end;
    while let Some(prev_node) = prev[&current] {
        path.push(current);
        current = prev_node;
    }
    path.push(start);
    path.reverse();

    (path, dist[&end])
}
