struct MinHeap<T> {
    data: Vec<T>,
}

impl<T: Ord> MinHeap<T> {
    pub fn new() -> Self {
        MinHeap { data: Vec::new() }
    }

    pub fn push(&mut self, item: T) {
        self.data.push(item);
        self.sift_up(self.data.len() - 1);
    }

    pub fn pop(&mut self) -> Option<T> {
        if self.data.is_empty() {
            None
        } else {
            let last_index = self.data.len() - 1;
            self.data.swap(0, last_index);
            let item = self.data.pop();
            self.sift_down(0);
            item
        }
    }

    pub fn peek(&self) -> Option<&T> {
        self.data.first()
    }

    fn sift_up(&mut self, mut index: usize) {
        while index > 0 {
            let parent = (index - 1) / 2;
            if self.data[parent] <= self.data[index] {
                break;
            }
            self.data.swap(parent, index);
            index = parent;
        }
    }

    fn sift_down(&mut self, mut index: usize) {
        let last_index = self.data.len() - 1;
        while index * 2 + 1 <= last_index {
            let left_child = index * 2 + 1;
            let right_child = left_child + 1;
            let smaller_child = if right_child <= last_index &&
                                   self.data[right_child] < self.data[left_child] {
                right_child
            } else {
                left_child
            };
            if self.data[smaller_child] >= self.data[index] {
                break;
            }
            self.data.swap(smaller_child, index);
            index = smaller_child;
        }
    }
}
