from abc import ABC, abstractmethod

class State(ABC):
    @abstractmethod
    def select_product(self):
        pass

    @abstractmethod
    def dispense(self):
        pass

    @abstractmethod
    def enter_maintenance(self):
        pass

class ReadyState(State):
    def select_product(self):
        print("Product selected. Dispensing...")
        return DispensingState()

    def dispense(self):
        print("No product selected.")
        return self

    def enter_maintenance(self):
        print("Entering maintenance mode.")
        return MaintenanceState()

class DispensingState(State):
    def select_product(self):
        print("Already dispensing. Please wait.")
        return self

    def dispense(self):
        print("Product dispensed. Returning to ready state.")
        return ReadyState()

    def enter_maintenance(self):
        print("Cannot enter maintenance mode while dispensing.")
        return self

class MaintenanceState(State):
    def select_product(self):
        print("In maintenance mode. Cannot select product.")
        return self

    def dispense(self):
        print("In maintenance mode. Cannot dispense.")
        return self

    def enter_maintenance(self):
        print("Exiting maintenance mode.")
        return ReadyState()

class VendingMachine:
    def __init__(self):
        self.state = ReadyState()

    def select_product(self):
        self.state = self.state.select_product()

    def dispense(self):
        self.state = self.state.dispense()

    def enter_maintenance(self):
        self.state = self.state.enter_maintenance()
