int edit_distance(char *str1, char *str2) {
    int len1 = strlen(str1);
    int len2 = strlen(str2);
    int *matrix = (int *)malloc((len1 + 1) * (len2 + 1) * sizeof(int));
    for (int i = 0; i <= len1; i++)
        matrix[i * (len2 + 1)] = i;
    for (int j = 0; j <= len2; j++)
        matrix[j] = j;
    for (int j = 1; j <= len2; j++) {
        for (int i = 1; i <= len1; i++) {
            int cost = (str1[i - 1] == str2[j - 1])? 0 : 1;
            int x = matrix[(i - 1) * (len2 + 1) + j] + 1;
            int y = matrix[i * (len2 + 1) + (j - 1)] + 1;
            int z = matrix[(i - 1) * (len2 + 1) + (j - 1)] + cost;
            matrix[i * (len2 + 1) + j] = min(x, y, z);
        }
    }
    int result = matrix[len1 * (len2 + 1) + len2];
    free(matrix);
    return result;
}

