    async fn from_request(request: &'r Request<'_>) -> request::Outcome<Self, Self::Error> {
        let next_param = request.query_value::<&str>("next").ok();        if let Some(next) = next_param {
            match Url::parse(next) {
                Ok(url) => {
                    if url.domain() == request.host().map(|h| h.domain()).as_deref() {
                        return request::Outcome::Success(NextUrl(url));
                    }
                }
                Err(_) => {}
            }
        }
        request::Outcome::Forward(())
    }
}

#[get("/")]fn index(next: Option<NextUrl>) -> Result<Redirect, Status> {
    match next {
        Some(NextUrl(url)) => Ok(Redirect::to(url.to_string())),
        None => Err(Status::BadRequest),
    }
