	visited := make(map[string]bool)
	var allPages []Page

	var crawl func(string)
	crawl = func(rawURL string) {
		if visited[rawURL] {
			return
		}
		visited[rawURL] = true

		resp, err := http.Get(rawURL)
		if err!= nil {
			log.Println(err)
			return
		}
		defer resp.Body.Close()

		doc, err := goquery.NewDocumentFromReader(resp.Body)
		if err!= nil {
			log.Println(err)
			return
		}

		var page Page
		page.URL = rawURL

		doc.Find("a[href]" ).Each(func(_ int, s *goquery.Selection) {
			href, _ := s.Attr("href")
			if!strings.HasPrefix(href, "http") {
				link := url.URL{
					Scheme: "https",
					Host:   "example.com",
					Path:   href,
				}
				href = link.String()
			}
			page.Links = append(page.Links, href)
			crawl(href)
		})

