package main

import (
    "container/list"
    "fmt"
)

type LRUCache struct {
    maxSize int
    items   map[int]*list.Element
    lruList *list.List
}

type cacheItem struct {
    key   int
    value int
}

func NewLRUCache(size int) *LRUCache {
    return &LRUCache{
        maxSize: size,
        items:   make(map[int]*list.Element),
        lruList: list.New(),
    }
}

func (c *LRUCache) Get(key int) int {
    if elem, ok := c.items[key]; ok {
        c.lruList.MoveToFront(elem)
        return elem.Value.(*cacheItem).value
    }
    return -1
}

func (c *LRUCache) Put(key, value int) {
    if elem, ok := c.items[key]; ok {
        c.lruList.MoveToFront(elem)
        elem.Value.(*cacheItem).value = value
    } else {
        if c.lruList.Len() >= c.maxSize {
            backElem := c.lruList.Back()
            delete(c.items, backElem.Value.(*cacheItem).key)
            c.lruList.Remove(backElem)
        }
        newElem := c.lruList.PushFront(&cacheItem{key: key, value: value})
        c.items[key] = newElem
    }
}

func main() {
    cache := NewLRUCache(3)
    cache.Put(1, 10)
    cache.Put(2, 20)
    cache.Put(3, 30)
    fmt.Println(cache.Get(1)) // Output: 10
    cache.Put(4, 40)
    fmt.Println(cache.Get(2)) // Output: -1
    cache.Put(5, 50)
    fmt.Println(cache.Get(3)) // Output: -1
    fmt.Println(cache.Get(4)) // Output: 40
}
