#include <iostream>
#include <queue>
#include <thread>
#include <mutex>
#include <condition_variable>

std::mutex mtx;
std::condition_variable cv;
std::queue<int> jobQueue;
bool done = false;

void worker() {
    while (true) {
        std::unique_lock<std::mutex> lock(mtx);
        cv.wait(lock, [] { return!jobQueue.empty() || done; });

        if (done && jobQueue.empty())
            return;

        if (!jobQueue.empty()) {
            int job = jobQueue.front();
            jobQueue.pop();
            lock.unlock();
            std::cout << "Processing job " << job << std::endl;
            // Process the job...
        }
    }
}

int main() {
    const int numWorkers = 4;
    std::vector<std::thread> workers;

    for (int i = 0; i < numWorkers; ++i) {
        workers.emplace_back(worker);
    }

    for (int i = 0; i < 10; ++i) {
        std::unique_lock<std::mutex> lock(mtx);
        jobQueue.push(i);
        lock.unlock();
        cv.notify_one();
    }

    std::this_thread::sleep_for(std::chrono::seconds(1));

    done = true;
    cv.notify_all();

    for (auto& worker : workers) {
        worker.join();
    }

    std::cout << "All jobs processed." << std::endl;

    return 0;
}

