use std::sync::{Arc, Condvar, Mutex};
use std::thread;
use std::collections::VecDeque;

type Job = Box<dyn FnOnce() + Send + 'static>;

struct Worker {
    thread: Option<thread::JoinHandle<()>>,
}

impl Worker {
    fn new(id: usize, jobs: Arc<(Mutex<VecDeque<Job>>, Condvar)>) -> Self {
        let thread = thread::Builder::new()
           .name(format!("worker-{}", id))
           .spawn(move || {
                let (lock, cvar) = &*jobs;
                loop {
                    let job = lock.lock().unwrap().pop_front();
                    if let Some(job) = job {
                        job();
                    } else {
                        cvar.wait_while(lock.lock().unwrap(), |queue| queue.is_empty()).unwrap();
                    }
                }
            })
           .ok();
        Self { thread }
    }
}

struct ThreadPool {
    workers: Vec<Worker>,
    jobs: Arc<(Mutex<VecDeque<Job>>, Condvar)>,
}

impl ThreadPool {
    fn new(size: usize) -> Self {
        let jobs = Arc::new((Mutex::new(VecDeque::new()), Condvar::new()));
        let mut workers = Vec::with_capacity(size);
        for id in 0..size {
            workers.push(Worker::new(id, jobs.clone()));
        }
        Self { workers, jobs }
    }

    fn execute<F>(&self, job: F)
    where
        F: FnOnce() + Send + 'static,
    {
        let (lock, cvar) = &*self.jobs;
        lock.lock().unwrap().push_back(Box::new(job));
        cvar.notify_one();
    }
}

impl Drop for ThreadPool {
    fn drop(&mut self) {
        let (lock, cvar) = &*self.jobs;
        lock.lock().unwrap().clear();
        cvar.notify_all();
        for worker in &mut self.workers {
            if let Some(thread) = worker.thread.take() {
                thread.join().unwrap();
            }
        }
    }
}

fn main() {
    let pool = ThreadPool::new(4);
    for _ in 0..8 {
        pool.execute(|| {
            println!("Processing job");
        });
    }
}
